import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Command, Sparkles } from 'lucide-react';
import { bridgeFetch } from '../lib/utils';
import FocusTrap from './FocusTrap';

interface CommandItem {
  id: string;
  icon: string;
  label: string;
  shortcut?: string;
  category: string;
  action: () => void;
}

export default function CommandPalette() {
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [mode, setMode] = useState<'commands' | 'ai'>('commands');
  const [aiResponse, setAiResponse] = useState<string | null>(null);
  const [aiLoading, setAiLoading] = useState(false);
  const [recentCommands, setRecentCommands] = useState<string[]>([]);
  const inputRef = useRef<HTMLInputElement>(null);
  const navigate = useNavigate();

  // Load recent commands from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('nexus-recent-commands');
    if (saved) {
      setRecentCommands(JSON.parse(saved).slice(0, 5));
    }
  }, []);

  // Detect if user is asking AI
  useEffect(() => {
    const looksLikeQuestion = search.startsWith('?') ||
      search.toLowerCase().startsWith('how') ||
      search.toLowerCase().startsWith('what') ||
      search.toLowerCase().startsWith('why') ||
      search.toLowerCase().startsWith('can you') ||
      search.toLowerCase().startsWith('help me');

    if (looksLikeQuestion && search.length > 5) {
      setMode('ai');
    } else {
      setMode('commands');
    }
  }, [search]);

  const saveRecentCommand = (cmdId: string) => {
    const updated = [cmdId, ...recentCommands.filter(r => r !== cmdId)].slice(0, 5);
    setRecentCommands(updated);
    localStorage.setItem('nexus-recent-commands', JSON.stringify(updated));
  };

  const commands: CommandItem[] = [
    { id: 'dashboard', icon: '≡ƒôè', label: 'Go to Dashboard', shortcut: 'G D', category: 'Navigation', action: () => navigate('/dashboard') },
    { id: 'chat', icon: '≡ƒÆ¼', label: 'Neural Hub (Chat)', shortcut: 'G C', category: 'AI', action: () => navigate('/chat') },
    { id: 'agents', icon: '≡ƒñû', label: 'Agent Headquarters', shortcut: 'G A', category: 'AI', action: () => navigate('/agents') },
    { id: 'news', icon: '≡ƒô░', label: 'Go to News', shortcut: 'G N', category: 'Navigation', action: () => navigate('/news') },
    { id: 'labs', icon: '≡ƒö¼', label: 'AI Labs', shortcut: 'G L', category: 'AI', action: () => navigate('/labs') },
    { id: 'pipeline', icon: '≡ƒÜÇ', label: 'Go to Pipeline', shortcut: 'G P', category: 'Navigation', action: () => navigate('/pipeline') },
    { id: 'settings', icon: 'ΓÜÖ∩╕Å', label: 'Settings', shortcut: 'G S', category: 'Navigation', action: () => navigate('/settings') },
    { id: 'studios', icon: '≡ƒÄ¿', label: 'Studios', category: 'Creative', action: () => navigate('/studios') },
  ];

  const filteredCommands = search
    ? commands.filter(cmd =>
      cmd.label.toLowerCase().includes(search.toLowerCase()) ||
      cmd.category.toLowerCase().includes(search.toLowerCase())
    )
    : commands;

  const groupedCommands = filteredCommands.reduce((acc, cmd) => {
    if (!acc[cmd.category]) acc[cmd.category] = [];
    acc[cmd.category].push(cmd);
    return acc;
  }, {} as Record<string, CommandItem[]>);

  const flatCommands = filteredCommands;

  async function handleAiQuery() {
    if (!search.trim()) return;
    setAiLoading(true);
    setAiResponse(null);

    try {
      const query = search.startsWith('?') ? search.slice(1).trim() : search;
      const response = await bridgeFetch('/llm/chat', {
        method: 'POST',
        body: JSON.stringify({
          messages: [
            { role: 'system', content: 'You are Lux, the AI assistant for Nexus. Be very concise.' },
            { role: 'user', content: query }
          ]
        })
      });

      const data = await response.json();
      setAiResponse(data.content || 'I could not process that request.');
    } catch {
      setAiResponse('AI is offline. Ensure Bridge is running.');
    } finally {
      setAiLoading(false);
    }
  }

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setOpen(prev => !prev);
        setSearch('');
        setSelectedIndex(0);
        setAiResponse(null);
        setMode('commands');
      }

      if (e.key === 'Escape') {
        setOpen(false);
      }

      if (open && mode === 'commands') {
        if (e.key === 'ArrowDown') {
          e.preventDefault();
          setSelectedIndex(prev => Math.min(prev + 1, flatCommands.length - 1));
        }
        if (e.key === 'ArrowUp') {
          e.preventDefault();
          setSelectedIndex(prev => Math.max(prev - 1, 0));
        }
        if (e.key === 'Enter' && flatCommands[selectedIndex]) {
          e.preventDefault();
          saveRecentCommand(flatCommands[selectedIndex].id);
          flatCommands[selectedIndex].action();
          setOpen(false);
        }
      }

      if (open && mode === 'ai' && e.key === 'Enter') {
        e.preventDefault();
        handleAiQuery();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [open, selectedIndex, flatCommands, mode, search]);

  if (!open) return null;

  return (
    <>
      <div
        className="fixed inset-0 z-[110] bg-black/70 backdrop-blur-md animate-in fade-in duration-150"
        onClick={() => setOpen(false)}
        aria-hidden="true"
      />

      <div className="fixed top-[15%] left-1/2 -translate-x-1/2 z-[120] w-full max-w-2xl px-4 animate-in fade-in zoom-in-95 slide-in-from-top-4 duration-150">
        <FocusTrap isActive={open} onEscape={() => setOpen(false)}>
          <div role="dialog" aria-modal="true" aria-label="Command palette" className="bg-[#0a0a0f]/95 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl overflow-hidden glass-panel">
            <div className="flex items-center gap-3 p-4 border-b border-white/5">
              <div className="p-2 bg-gradient-to-br from-cyan-500/20 to-purple-500/20 rounded-lg">
                {mode === 'ai' ? <Sparkles size={20} className="text-cyan-400" /> : <Command size={20} className="text-cyan-400" />}
              </div>
              <input
                ref={inputRef}
                type="text"
                placeholder={mode === 'ai' ? "Ask Lux anything..." : "Search commands... (? for AI)"}
                value={search}
                onChange={(e) => {
                  setSearch(e.target.value);
                  setSelectedIndex(0);
                }}
                className="flex-1 bg-transparent focus:outline-none text-lg text-white placeholder-gray-500"
                autoFocus
                aria-label="Search commands or ask AI"
                role="combobox"
                aria-expanded={mode === 'commands' && filteredCommands.length > 0}
                aria-autocomplete="list"
                aria-controls="command-list"
              />
              <div className="flex items-center gap-2">
                {mode === 'ai' && <span className="px-2 py-1 bg-purple-500/20 rounded text-xs text-purple-400 border border-purple-500/30">AI Mode</span>}
                <kbd className="px-2 py-1 bg-white/5 rounded text-xs text-gray-500 border border-white/10">ESC</kbd>
              </div>
            </div>

            {mode === 'ai' && (aiLoading || aiResponse) && (
              <div className="p-4 border-b border-white/5 bg-purple-500/5">
                {aiLoading ? (
                  <div className="flex items-center gap-2 text-gray-400">
                    <Sparkles size={16} className="animate-spin" />
                    <span>Thinking...</span>
                  </div>
                ) : (
                  <div className="flex items-start gap-3">
                    <div className="w-6 h-6 rounded-full bg-gradient-to-br from-cyan-500 to-purple-500 flex items-center justify-center text-xs">Γ£¿</div>
                    <p className="text-gray-300 text-sm">{aiResponse}</p>
                  </div>
                )}
              </div>
            )}

            <div className="flex gap-1 p-2 border-b border-white/5 bg-white/[0.02]" role="tablist" aria-label="Command palette modes">
              <button onClick={() => setMode('commands')} role="tab" aria-selected={mode === 'commands'} className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${mode === 'commands' ? 'bg-cyan-500/20 text-cyan-400' : 'text-gray-500 hover:text-gray-300'}`}>Commands</button>
              <button onClick={() => { setMode('ai'); inputRef.current?.focus(); }} role="tab" aria-selected={mode === 'ai'} className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors flex items-center gap-1 ${mode === 'ai' ? 'bg-purple-500/20 text-purple-400' : 'text-gray-500 hover:text-gray-300'}`}><Sparkles size={12} aria-hidden="true" /> Ask AI</button>
            </div>

            {mode === 'commands' && (
              <div id="command-list" role="listbox" aria-label="Available commands" className="max-h-[350px] overflow-y-auto custom-scrollbar">
                {Object.entries(groupedCommands).map(([category, cmds]) => (
                  <div key={category}>
                    <div className="px-4 py-2 text-xs text-gray-500 uppercase tracking-wide bg-white/[0.02]">{category}</div>
                    {cmds.map((cmd) => {
                      const index = flatCommands.findIndex(c => c.id === cmd.id);
                      const isSelected = index === selectedIndex;
                      return (
                        <button
                          key={cmd.id}
                          role="option"
                          aria-selected={isSelected}
                          className={`w-full flex items-center justify-between px-4 py-3 text-left transition-colors ${isSelected ? 'bg-cyan-500/20 text-white' : 'hover:bg-white/5 text-gray-400'}`}
                          onClick={() => { saveRecentCommand(cmd.id); cmd.action(); setOpen(false); }}
                          onMouseEnter={() => setSelectedIndex(index)}
                        >
                          <div className="flex items-center gap-3">
                            <span className="text-xl">{cmd.icon}</span>
                            <span>{cmd.label}</span>
                          </div>
                          {cmd.shortcut && <kbd className="px-2 py-1 bg-white/5 rounded text-xs text-gray-500 border border-white/10">{cmd.shortcut}</kbd>}
                        </button>
                      );
                    })}
                  </div>
                ))}
              </div>
            )}

            <div className="flex items-center justify-between px-4 py-2 border-t border-white/5 text-xs text-gray-500 bg-black/20">
              <div className="flex gap-4"><span>ΓåæΓåô Navigate</span><span>Γå╡ Select</span><span>? AI Mode</span></div>
              <span className="flex items-center gap-1"><Command size={12} />K to toggle</span>
            </div>
          </div>
        </FocusTrap>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Loader2 } from 'lucide-react';
import type { NewsItem } from '../../../types/dashboard';
import { SAMPLE_NEWS } from '../../../config/dashboardConfig';
import { fetchAllNews } from '../../../services/newsService';

export function NewsWidget() {
    const [news, setNews] = useState<NewsItem[]>(SAMPLE_NEWS);
    const [loadingNews, setLoadingNews] = useState(true);

    useEffect(() => {
        fetchDashboardNews();
    }, []);

    function getTimeAgo(dateStr: string) {
        const diff = Date.now() - new Date(dateStr).getTime();
        const hrs = Math.floor(diff / (1000 * 60 * 60));
        if (hrs < 1) return 'Just now';
        if (hrs > 24) return `${Math.floor(hrs / 24)}d ago`;
        return `${hrs}h ago`;
    }

    async function fetchDashboardNews() {
        try {
            const allArticles = await fetchAllNews();
            const combined = allArticles
                .sort((a, b) => new Date(b.pubDate).getTime() - new Date(a.pubDate).getTime())
                .slice(0, 5)
                .map(item => ({
                    title: item.title,
                    source: item.source.name || 'Unknown',
                    time: getTimeAgo(item.pubDate),
                    link: item.link
                }));
            if (combined.length > 0) setNews(combined);
        } catch { } finally { setLoadingNews(false); }
    }

    return (
        <div className="flex flex-col h-[60%] overflow-y-auto pr-1">
            {loadingNews ? (
                <div className="text-gray-500 text-sm animate-pulse flex items-center gap-2">
                    <Loader2 className="w-4 h-4 animate-spin"/> Loading feeds...
                </div>
            ) : (
                news.map((item: NewsItem, i: number) => (
                    <div key={i} className="border-b border-white/5 last:border-0 pb-3 mb-3 last:pb-0 last:mb-0">
                        <a href={item.link} target="_blank" rel="noopener noreferrer" className="group block">
                            <p className="text-sm font-medium group-hover:text-cyan-400 transition-colors line-clamp-2 text-white/90">{item.title}</p>
                            <p className="text-[10px] uppercase tracking-widest font-bold text-gray-500 mt-1.5 flex justify-between">
                                <span className="text-white/40">{item.source}</span><span className="font-mono">{item.time}</span>
                            </p>
                        </a>
                    </div>
                ))
            )}
            <Link to="/news" className="text-xs text-cyan-400 hover:text-cyan-300 font-bold uppercase tracking-widest mt-auto pt-2 block w-max mt-4">Open Neural News &rarr;</Link>
        </div>
    );
}

"use client";
import { useState, useEffect } from 'react';

import { loadFromStorage, saveToStorage, storageKey } from '@/lib/smartfolio/storage';

interface CoinData {
    id: string;
    description: { en: string };
    market_data: {
        market_cap: { usd: number };
        total_volume: { usd: number };
        ath: { usd: number };
        ath_change_percentage: { usd: number };
        circulating_supply: number;
        max_supply: number;
        price_change_percentage_24h: number;
        price_change_percentage_7d: number;
        price_change_percentage_30d: number;
        price_change_percentage_1y: number;
    };
    links: {
        homepage: string[];
        twitter_screen_name: string;
    };
}

const CACHE_DURATION = 60 * 60 * 1000; // 1 hour

// Mapping for common symbols to CoinGecko IDs
const ID_MAP: Record<string, string> = {
    'BTC': 'bitcoin',
    'ETH': 'ethereum',
    'SOL': 'solana',
    'SUI': 'sui',
    'AAVE': 'aave',
    'LINK': 'chainlink',
    'UNI': 'uniswap',
    'IMX': 'immutable-x',
    'ARB': 'arbitrum',
    'OP': 'optimism',
    'RENDER': 'render-token',
    'FET': 'fetch-ai',
    'INJ': 'injective-protocol',
    'TIA': 'celestia',
    'SEI': 'sei-network',
    'PEPE': 'pepe',
    'DOGE': 'dogecoin',
    'XRP': 'ripple',
    'ADA': 'cardano',
    'DOT': 'polkadot',
    'MATIC': 'matic-network',
    'ONDO': 'ondo-finance',
    'HYPE': 'hyperliquid',
    'HBAR': 'hedera-hashgraph',
};

export default function CoinResearch({ symbol }: { symbol: string }) {
    const [data, setData] = useState<CoinData | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [isStale, setIsStale] = useState(false);

    useEffect(() => {
        let mounted = true;
        const fetchCoinData = async () => {
            if (!symbol || symbol === 'USD') {
                setLoading(false);
                return;
            }

            const id = ID_MAP[symbol.toUpperCase()] || symbol.toLowerCase();
            const cacheKey = storageKey('coin', id);

            // 1. Initial State from Cache (Stale-While-Revalidate)
            const cached = loadFromStorage<{ timestamp: number; payload: CoinData } | null>(cacheKey, null);
            let hasFreshCache = false;

            if (cached) {
                const age = Date.now() - cached.timestamp;
                if (age < CACHE_DURATION) {
                    setData(cached.payload);
                    setLoading(false);
                    hasFreshCache = true;
                } else {
                    // Cache expired, but show it while we fetch
                    setData(cached.payload);
                    setIsStale(true);
                }
            }

            // 2. Fetch Fresh if needed
            if (hasFreshCache) return;

            try {
                // If we don't even have stale data, show loader
                if (!cached) setLoading(true);
                
                const res = await fetch(`https://api.coingecko.com/api/v3/coins/${id}?localization=false&tickers=false&community_data=false&developer_data=false&sparkline=false`);

                if (!res.ok) {
                    if (res.status === 429) throw new Error('RATE_LIMIT');
                    throw new Error('Coin not found');
                }

                const json = await res.json();

                if (mounted) {
                    setData(json);
                    setIsStale(false);
                    setError(null);
                    saveToStorage(cacheKey, {
                        timestamp: Date.now(),
                        payload: json
                    });
                }
            } catch (err: any) {
                console.warn(`[CoinResearch] API failed for ${id}`, err);
                
                if (mounted) {
                    // If we have any data (even stale), keep it and just mark it stale
                    if (data || cached) {
                        setIsStale(true);
                        // Optional: show a silent warning?
                    } else {
                        setError(err.message === 'RATE_LIMIT' ? 'Rate limited by CoinGecko' : 'Research data unavailable');
                    }
                }
            } finally {
                if (mounted) setLoading(false);
            }
        };

        fetchCoinData();
        return () => { mounted = false; };
    }, [symbol]);

    if (symbol === 'USD') return null;

    if (loading) return (
        <div className="p-4 animate-pulse space-y-3">
            <div className="h-4 bg-white/5 rounded w-1/3"></div>
            <div className="h-12 bg-white/5 rounded w-full"></div>
            <div className="grid grid-cols-2 gap-4">
                <div className="h-8 bg-white/5 rounded"></div>
                <div className="h-8 bg-white/5 rounded"></div>
            </div>
        </div>
    );

    if (error || !data) return (
        <div className="p-4 text-[10px] text-gray-500 font-mono text-center border border-white/5 rounded-lg bg-white/[0.02]">
            {error || 'No data found'} {symbol}
        </div>
    );

    // Parse description - remove HTML links
    const rawDesc = data.description?.en || '';
    const desc = rawDesc ? rawDesc.split('. ')[0] + '.' : 'No description available for this asset.';
    const cleanDesc = desc.replace(/<[^>]*>?/gm, '');

    const fmt = (n: number) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);
    const fmtNum = (n: number) => new Intl.NumberFormat('en-US', { notation: 'compact', compactDisplay: 'short' }).format(n);

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in-up">
            {/* Fundamentals */}
            <div className="space-y-4">
                <h4 className="text-[10px] font-black text-amber-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    Start-Up Fundamentals
                    {isStale ? (
                        <span className="px-1.5 py-0.5 rounded-sm bg-amber-500/10 border border-amber-500/20 text-[8px] text-amber-500 animate-pulse">
                            CACHED
                        </span>
                    ) : (
                        <span className="w-1.5 h-1.5 rounded-full bg-amber-500"></span>
                    )}
                </h4>

                <p className="text-xs text-gray-400 leading-relaxed font-medium line-clamp-3">
                    {cleanDesc}
                </p>

                <div className="grid grid-cols-2 gap-y-3 gap-x-6">
                    <div>
                        <div className="text-[9px] text-gray-600 uppercase tracking-widest">Market Cap</div>
                        <div className="text-sm font-mono text-white font-bold">{fmt(data.market_data.market_cap.usd)}</div>
                    </div>
                    <div>
                        <div className="text-[9px] text-gray-600 uppercase tracking-widest">FDV / Volume</div>
                        <div className="text-sm font-mono text-white font-bold">
                            {fmtNum(data.market_data.total_volume.usd)} <span className="text-[9px] text-gray-500 font-normal">24h Vol</span>
                        </div>
                    </div>
                    <div>
                        <div className="text-[9px] text-gray-600 uppercase tracking-widest">Supply</div>
                        <div className="text-xs font-mono text-white">
                            {fmtNum(data.market_data.circulating_supply)} / {data.market_data.max_supply ? fmtNum(data.market_data.max_supply) : 'Γê₧'}
                        </div>
                    </div>
                    <div>
                        <div className="text-[9px] text-gray-600 uppercase tracking-widest">ATH Drawdown</div>
                        <div className="text-xs font-mono text-rose-400 font-bold">
                            {data.market_data.ath_change_percentage.usd.toFixed(1)}%
                        </div>
                        <div className="text-[8px] text-gray-600">Peak: {fmt(data.market_data.ath.usd)}</div>
                    </div>
                </div>

                <div className="flex gap-3 pt-2">
                    {data.links.homepage[0] && (
                        <a href={data.links.homepage[0]} target="_blank" rel="noreferrer" className="text-[9px] text-blue-400 hover:text-white uppercase tracking-wider font-bold border-b border-blue-400/30 hover:border-blue-400 pb-0.5 transition-all">
                            Website Γåù
                        </a>
                    )}
                    {data.links.twitter_screen_name && (
                        <a href={`https://twitter.com/${data.links.twitter_screen_name}`} target="_blank" rel="noreferrer" className="text-[9px] text-blue-400 hover:text-white uppercase tracking-wider font-bold border-b border-blue-400/30 hover:border-blue-400 pb-0.5 transition-all">
                            Twitter Γåù
                        </a>
                    )}
                </div>
            </div>

            {/* AI Analysis Stub + Momentum */}
            <div className="flex flex-col gap-4">
                <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5 flex flex-col justify-center items-center text-center space-y-2 flex-1">
                    <span className="text-2xl opacity-20">≡ƒºá</span>
                    <p className="text-[10px] text-gray-500 font-mono max-w-[200px]">
                        Combined with portfolio data, this asset represents {((data.market_data.market_cap.usd / 1e9) > 10) ? 'Large Cap Stability' : 'High Growth Potential'}.
                    </p>
                </div>

                {/* Multi-Timeframe Performance */}
                <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5">
                    <h5 className="text-[9px] font-black text-gray-500 uppercase tracking-widest mb-3 text-center">Momentum</h5>
                    <div className="grid grid-cols-4 gap-2">
                        <Momentum label="24h" val={data.market_data.price_change_percentage_24h} />
                        <Momentum label="7d" val={data.market_data.price_change_percentage_7d} />
                        <Momentum label="30d" val={data.market_data.price_change_percentage_30d} />
                        <Momentum label="1y" val={data.market_data.price_change_percentage_1y} />
                    </div>
                </div>
            </div>
        </div>
    );
}

function Momentum({ label, val }: { label: string; val: number | undefined | null }) {
    if (val === undefined || val === null) return (
        <div className="flex flex-col items-center opacity-30">
            <span className="text-[8px] text-gray-500 uppercase">{label}</span>
            <span className="text-xs font-mono font-bold text-gray-500">ΓÇö</span>
        </div>
    );

    return (
        <div className="flex flex-col items-center">
            <span className="text-[8px] text-gray-500 uppercase">{label}</span>
            <span className={`text-xs font-mono font-bold ${val >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                {val > 0 ? '+' : ''}{val.toFixed(1)}%
            </span>
        </div>
    );
}

import { createContext, useContext, useState, useEffect } from 'react';
import type { ReactNode } from 'react';

export interface User {
  id: string;
  email: string;
  name: string;
  picture?: string;
}

interface AuthContextValue {
  user: User | null;
  loading: boolean;
  login: () => void;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>({ 
    id: 'dlx-admin', 
    email: 'admin@dlxstudios.online', 
    name: 'Chris Barclay (Dev Override)' 
  });
