export function Chat() {
  const { toast } = useToast();
  const location = useLocation();

  // --- State ---
  const [viewMode, setViewMode] = useState<'agents' | 'models'>('agents');
  const [sidebarOpen, setSidebarOpen] = useState(() => window.innerWidth >= 768);

  // Chat State
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [streaming, setStreaming] = useState('');

  // Agent Mode State
  const [activeAgentId, setActiveAgentId] = useState(location.state?.agentId || 'lux');

  // Model Mode State
  const [localModels, setLocalModels] = useState<{ lmstudio: DiscoveredModel[], ollama: DiscoveredModel[] }>({ lmstudio: [], ollama: [] });
  const [selectedModel, setSelectedModel] = useState<{ provider: 'lmstudio' | 'ollama', id: string } | null>(null);
  const [customSystemPrompt, setCustomSystemPrompt] = useState('You are a helpful AI assistant connected to the Nexus Neural Hub.');
  const [showPromptEditor, setShowPromptEditor] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);
  const activeAgent = AGENTS.find(a => a.id === activeAgentId) || AGENTS[0];

  // --- Actions ---
  async function fetchAllModels() {
    try {
      const res = await fetch(`${import.meta.env.VITE_API_URL || ''}/api/llm/status`, { cache: 'no-store' });
      if (!res.ok) return;
      const data = await res.json();
      
      const ollamaModels = data.ollama ? [{ id: data.activeModel || 'qwen3:8b', name: data.activeModel || 'Ollama Default', size: 4000000000 }] : [];
      const lmStudioModels = data.lmStudio ? [{ id: data.activeModel || 'lmstudio-local', name: 'LM Studio Default', size: 4000000000 }] : [];

      setLocalModels({
        lmstudio: lmStudioModels,
        ollama: ollamaModels
      });

      if (!selectedModel) {
        if (ollamaModels.length > 0) setSelectedModel({ provider: 'ollama', id: ollamaModels[0].id });
        else if (lmStudioModels.length > 0) setSelectedModel({ provider: 'lmstudio', id: lmStudioModels[0].id });
      }

    } catch (e) {
      console.error('Failed to fetch models', e);
    }
  }

  // --- Effects ---
  useEffect(() => {
    const saved = localStorage.getItem('nexus-chat-messages');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setMessages(parsed.map((m: any) => ({ ...m, timestamp: new Date(m.timestamp) })));
      } catch (e) {}
    }
    fetchAllModels();
  }, []);

  useEffect(() => {
    if (messages.length > 0) {
      // Keep last 100 messages to avoid localStorage quota exhaustion
      const trimmed = messages.slice(-100);
      try {
        localStorage.setItem('nexus-chat-messages', JSON.stringify(trimmed));
      } catch { /* quota exceeded ΓÇö skip */ }
    }
  }, [messages]);

  useEffect(() => {
    if (messages.length === 0 && viewMode === 'agents') {
      setMessages([{
        id: '0',
        role: 'assistant',
        content: `**Neural Hub Online.**\n\nI am Lux, your primary interface. Select an agent to collaborate, or switch to "Models" tab to inspect and drive local LLMs directly.`,
        timestamp: new Date(),
        agentId: 'lux'
      }]);
    }
  }, [viewMode]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, streaming]);

  const clearChat = () => {
    if (!window.confirm('Clear all chat history? This cannot be undone.')) return;
    setMessages([]);
    localStorage.removeItem('nexus-chat-messages');
    fetch(`${import.meta.env.VITE_API_URL || ''}/api/chat`, { method: 'DELETE' }).catch(console.error);
  };

  async function sendMessage() {
    if (!input.trim() || loading) return;

    if (viewMode === 'models' && !selectedModel) {
      toast.error("Please select an engine first.");
      return;
    }

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input.trim(),
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);
    setStreaming('');

    try {
      await fetch(`${import.meta.env.VITE_API_URL || ''}/api/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ role: 'user', content: userMsg.content }),
      }).catch(console.error);

      const reqSystem = viewMode === 'agents' ? activeAgent.systemPrompt : customSystemPrompt;

      let res;
      // In cloud, always use Gemini for debate. So just use it for models too.
      const debateMessages = [...messages, userMsg]
        .filter(m => m.role === 'user' || m.role === 'agent')
        .map(m => ({
          role: m.role === 'user' ? 'user' : 'assistant',
          content: m.content
        }));
      res = await fetch(`${import.meta.env.VITE_API_URL || ''}/api/debate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          messages: debateMessages,
          systemPrompt: reqSystem,
          agentName: viewMode === 'agents' ? activeAgent?.name : selectedModel?.id
        }),
      });

      if (!res.ok) throw new Error('LLM request failed');

      const data = await res.json();
      const reply = data.text || "No response.";

      // Stream simulation
      for (let i = 0; i <= reply.length; i += 8) {
        setStreaming(reply.slice(0, i));
        await new Promise(r => setTimeout(r, 5));
      }
      setStreaming('');

      const assistantMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'agent',
        content: reply,
        timestamp: new Date(),
        agentId: viewMode === 'agents' ? activeAgentId : selectedModel?.id
      };

      setMessages(prev => [...prev, assistantMsg]);

      await fetch(`${import.meta.env.VITE_API_URL || ''}/api/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ role: 'assistant', content: reply }),
      }).catch(console.error);

    } catch (e: any) {
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'system',
        content: "Γ¥î Connection to Local LLM failed. Make sure Ollama/LM Studio is running.",
        timestamp: new Date()
      }]);
    } finally {
      setLoading(false);
      setStreaming('');
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }



  return (
    <PageLayout color="cyan" noPadding>
      <div className="flex h-[calc(100vh-64px)] relative overflow-hidden">
        
        {/* Workspace Sidebar */}
        <m.aside
          animate={{ width: sidebarOpen ? 300 : 80 }}
          className="border-r border-white/5 bg-black/40 backdrop-blur-xl flex flex-col shrink-0 relative z-20 shadow-2xl transition-all"
          aria-label="Chat workspace"
        >
          <div className="p-8 border-b border-white/5 flex items-center justify-between">
            {sidebarOpen && (
              <div className="flex flex-col">
                <span className="text-[10px] uppercase font-black tracking-[0.4em] text-cyan-400 mb-1.5 leading-none">Neural Link</span>
                <span className="text-xl font-black text-white tracking-tighter leading-none">WORKSPACE</span>
              </div>
            )}
            <button
              onClick={() => setSidebarOpen(!sidebarOpen)}
              className={`w-8 h-8 rounded-lg bg-white/5 border border-white/10 flex items-center justify-center text-white/30 hover:text-white transition-all ${!sidebarOpen && 'mx-auto'}`}
              aria-label={sidebarOpen ? 'Collapse sidebar' : 'Expand sidebar'}
              aria-expanded={sidebarOpen}
            >
              <ChevronRight size={16} className={`transition-transform ${sidebarOpen ? 'rotate-180' : ''}`} aria-hidden="true" />
            </button>
          </div>

          {sidebarOpen && (
            <div className="p-4">
              <div className="flex bg-white/5 rounded-xl p-1 border border-white/5 shadow-inner">
                <button
                  onClick={() => setViewMode('agents')}
                  className={`flex-1 py-1.5 text-[9px] font-black uppercase tracking-widest rounded-lg transition-all ${viewMode === 'agents' ? 'bg-cyan-500/20 text-cyan-400 border border-cyan-500/30' : 'text-white/20 hover:text-white'}`}
                >
                  Personas
                </button>
                <button
                  onClick={() => setViewMode('models')}
                  className={`flex-1 py-1.5 text-[9px] font-black uppercase tracking-widest rounded-lg transition-all ${viewMode === 'models' ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30' : 'text-white/20 hover:text-white'}`}
                >
                  Engines
                </button>
              </div>
            </div>
          )}

          <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-1">
            {viewMode === 'agents' ? (
              AGENTS.map((agent) => {
                const Icon = agent.icon;
                const isActive = activeAgentId === agent.id;
                return (
                  <button
                    key={agent.id}
                    onClick={() => setActiveAgentId(agent.id)}
                    className={`group w-full flex items-center gap-4 p-3 rounded-xl transition-all border relative ${isActive ? 'bg-cyan-500/10 border-cyan-500/30 text-white' : 'hover:bg-white/[0.03] border-transparent text-white/30 hover:text-white'}`}
                  >
                    {isActive && sidebarOpen && <m.div layoutId="active-chat-marker" className="absolute left-1.5 top-3 bottom-3 w-0.5 bg-cyan-500 rounded-full" />}
                    <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 bg-black/40 border transition-all ${isActive ? 'border-cyan-500/30 text-cyan-400' : 'border-white/5'}`}>
                      <Icon size={18} />
                    </div>
                    {sidebarOpen && (
                      <div className="text-left flex-1 min-w-0">
                        <div className="text-xs font-black truncate uppercase tracking-tight">{agent.name}</div>
                        <div className="text-[8px] font-black uppercase tracking-widest opacity-30 mt-0.5">{agent.role}</div>
                      </div>
                    )}
                  </button>
                );
              })
            ) : (
              <div className="space-y-4">
                 {/* Simplified Model Listing */}
                 {localModels.ollama.map(m => (
                    <button
                      key={m.id}
                      onClick={() => setSelectedModel({ provider: 'ollama', id: m.id })}
                      className={`group w-full flex items-center gap-4 p-3 rounded-xl transition-all border ${selectedModel?.id === m.id ? 'bg-purple-500/10 border-purple-500/30 text-white' : 'hover:bg-white/[0.03] border-transparent text-white/30'}`}
                    >
                      <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 bg-black/40 border ${selectedModel?.id === m.id ? 'border-purple-500/30 text-purple-400' : 'border-white/5'}`}>
                        <Database size={16} />
                      </div>
                      {sidebarOpen && (
                        <div className="text-left flex-1 min-w-0">
                          <div className="text-[10px] font-black truncate uppercase tracking-tight">{m.id}</div>
                          <div className="text-[7px] font-black uppercase tracking-widest opacity-30 mt-1">Ollama Native</div>
                        </div>
                      )}
                    </button>
                 ))}
              </div>
            )}
          </div>
        </m.aside>

        {/* Primary Interaction Field */}
        <main className="flex-1 flex flex-col relative z-10">
          
          {/* Sub-Header HUD */}
          <div className="px-6 py-4 flex items-center justify-between border-b border-white/5 bg-black/10 backdrop-blur-sm">
             <div className="flex items-center gap-4">
                {viewMode === 'agents' ? (
                  <>
                    <div className={`w-10 h-10 rounded-xl border flex items-center justify-center shrink-0 ${activeAgent.color.replace('text-', 'bg-')}/10 ${activeAgent.color.replace('text-', 'border-')}/40`}>
                      <activeAgent.icon className={activeAgent.color} size={20} />
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <span className="text-sm font-black text-white tracking-tight uppercase">{activeAgent.name}</span>
                        <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]" />
                      </div>
                      <div className="text-[8px] font-black uppercase tracking-[0.2em] text-white/30">{activeAgent.role}</div>
                    </div>
                  </>
                ) : (
                  <>
                    <div className="w-10 h-10 rounded-xl border bg-purple-500/10 border-purple-500/30 flex items-center justify-center shrink-0">
                      <Database className="text-purple-400" size={20} />
                    </div>
                    <div>
                      <span className="text-sm font-black text-white tracking-tight uppercase">{selectedModel?.id || 'NO_ENGINE_SELECTED'}</span>
                      <div className="text-[8px] font-black uppercase tracking-[0.2em] text-white/30">{selectedModel?.provider} Native Pipeline</div>
                    </div>
                  </>
                )}
             </div>

             <div className="flex items-center gap-2">
                {viewMode === 'models' && (
                   <button onClick={() => setShowPromptEditor(!showPromptEditor)} aria-label="Toggle system prompt editor" aria-expanded={showPromptEditor} className={`p-2 rounded-lg border transition-all ${showPromptEditor ? 'bg-purple-500/20 border-purple-500/40 text-purple-400' : 'bg-white/5 border-white/5 text-white/30 hover:text-white'}`}>
                      <Settings size={14} aria-hidden="true" />
                   </button>
                )}
                <button onClick={clearChat} className="p-2 rounded-lg bg-white/5 border border-white/5 text-white/20 hover:text-red-400 hover:bg-red-500/10 transition-all" aria-label="Clear chat history">
                  <Trash2 size={14} aria-hidden="true" />
                </button>
             </div>
          </div>

          {/* System Prompt Editor */}
          <AnimatePresence>
            {showPromptEditor && viewMode === 'models' && (
              <m.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0 }}
                className="overflow-hidden border-b border-white/5"
              >
                <div className="px-6 py-4 bg-purple-500/5">
                  <label className="text-[8px] font-black text-purple-400 uppercase tracking-[0.3em] mb-2 block">System Prompt</label>
                  <textarea
                    value={customSystemPrompt}
                    onChange={e => setCustomSystemPrompt(e.target.value)}
                    rows={4}
                    className="w-full glass-input border-purple-500/20 text-xs resize-none font-mono"
                    placeholder="You are a helpful AI assistant..."
                  />
                </div>
              </m.div>
            )}
          </AnimatePresence>

          {/* Buffer Message Field */}
          <div role="log" aria-label="Chat messages" aria-live="polite" className="flex-1 overflow-y-auto px-6 py-8 space-y-8 custom-scrollbar relative">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center opacity-40 select-none">
                <div className="text-[8px] font-black uppercase tracking-[0.4em] text-white/30 mb-2">NEURAL LINK READY</div>
                <div className="text-[9px] text-white/20">Send a message to begin.</div>
              </div>
            )}
            {messages.map((msg) => {
              const isUser = msg.role === 'user';
              const isSystem = msg.role === 'system';
              const agent = viewMode === 'agents' ? (AGENTS.find(a => a.id === msg.agentId) || AGENTS[0]) : { name: selectedModel?.id || 'Bridge', color: 'text-purple-400', icon: Database };
              const Icon = isUser ? User : isSystem ? Shield : agent.icon;

              return (
                <m.div
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  key={msg.id}
                  className={`flex gap-4 max-w-4xl mx-auto w-full ${isUser ? 'flex-row-reverse' : ''}`}
                >
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 border mt-1 shadow-xl ${isUser ? 'bg-white/5 border-white/10 text-white/40' : isSystem ? 'bg-red-500/10 border-red-500/30 text-red-400' : `${agent.color.replace('text-', 'bg-')}/10 ${agent.color.replace('text-', 'border-')}/40 ${agent.color}`}`}>
                    <Icon size={18} />
                  </div>
                  <div className={`flex flex-col ${isUser ? 'items-end' : 'items-start'} max-w-[85%] min-w-0`}>
                    <div className="flex items-center gap-3 mb-1.5 px-1 font-black uppercase text-[8px] tracking-[0.2em] opacity-30">
                      <span>{isUser ? 'LOCAL_USER' : isSystem ? 'KERNEL' : agent.name}</span>
                      <span>{msg.timestamp?.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <div className={`rounded-2xl p-4 text-sm leading-relaxed relative w-full border overflow-hidden ${isUser ? 'bg-cyan-500/10 border-cyan-500/30 text-white' : 'bg-white/[0.03] border-white/5 text-white/80'}`}>
                       {isUser || isSystem ? (
                         <p className="whitespace-pre-wrap">{msg.content}</p>
                       ) : (
                         <div className="flex flex-col gap-2">
                           {msg.content.split(/(<think>[\s\S]*?(?:<\/think>|$)|<save_note>[\s\S]*?(?:<\/save_note>|$)|<save_file name="[^"]+">[\s\S]*?(?:<\/save_file>|$))/gi).map((token, i) => {
                              if (/^<think>([\s\S]*?)(?:<\/think>|$)/i.test(token)) {
                                const inner = token.replace(/^<think>/i, '').replace(/<\/think>$/i, '').trim();
                                return (
                                  <details key={i} open className="group my-2 bg-black/20 rounded-lg border border-white/5 overflow-hidden">
                                    <summary className="cursor-pointer text-[10px] font-black uppercase tracking-[0.2em] text-cyan-500/50 hover:text-cyan-400 select-none p-3 flex items-center gap-2 bg-white/[0.02]">
                                       <span className="w-1.5 h-1.5 rounded-full bg-cyan-500/30 group-open:bg-cyan-500 animate-pulse" />
                                       Neural Processing Stream
                                    </summary>
                                    <div className="p-4 text-xs font-mono text-cyan-500/60 whitespace-pre-wrap border-t border-white/5">
                                       {inner || <span className="opacity-50">Initializing stream...</span>}
                                    </div>
                                  </details>
                                );
                              }
                              if (/^<save_note>([\s\S]*?)(?:<\/save_note>|$)/i.test(token)) {
                                const inner = token.replace(/^<save_note>/i, '').replace(/<\/save_note>$/i, '').trim();
                                return (
                                  <div key={i} className="my-2 p-3 rounded-lg border border-emerald-500/20 bg-emerald-500/10 flex gap-3 items-start text-emerald-400 shadow-lg shadow-emerald-500/5">
                                     <Database size={16} className="shrink-0 mt-0.5 opacity-80" />
                                     <div>
                                       <div className="text-[9px] font-black uppercase tracking-widest mb-1 opacity-60">Auto-Synced to Master Notes</div>
                                       <div className="text-sm italic">{inner || '...'}</div>
                                     </div>
                                  </div>
                                );
                              }
                              if (/^<save_file name="([^"]+)">([\s\S]*?)(?:<\/save_file>|$)/i.test(token)) {
                                const match = token.match(/^<save_file name="([^"]+)">([\s\S]*?)(?:<\/save_file>|$)/i);
                                const filename = match?.[1] || 'Unknown.md';
                                const content = match?.[2] || '';
                                return (
                                  <div key={i} className="my-3 p-4 rounded-xl border border-cyan-500/30 bg-cyan-900/10 flex flex-col gap-3 shadow-[0_0_15px_rgba(6,182,212,0.1)]">
                                     <div className="flex items-center gap-2 text-cyan-400">
                                        <Database size={16} />
                                        <span className="text-[10px] font-black uppercase tracking-widest">Saved to Google Drive</span>
                                     </div>
                                     <div className="text-white font-bold text-sm tracking-tight">{filename}</div>
                                     <div className="text-sm text-white/60 line-clamp-3 italic opacity-80 pl-2 border-l-2 border-cyan-500/30">{content.trim()}</div>
                                  </div>
                                );
                              }
                              return token.trim() ? (
                                <div key={i} className="prose prose-invert prose-p:leading-relaxed prose-pre:bg-black/50 prose-pre:p-4 prose-pre:rounded-xl prose-code:text-cyan-400 max-w-none">
                                   <ReactMarkdown remarkPlugins={[remarkGfm]}>{token}</ReactMarkdown>
                                </div>
                              ) : null;
                           })}
                         </div>
                       )}
                    </div>
                  </div>
                </m.div>
              );
            })}
            
            {streaming && (
              <div className="flex gap-4 max-w-4xl mx-auto w-full">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 border mt-1 animate-pulse ${viewMode === 'agents' ? `${activeAgent.color.replace('text-', 'bg-')}/10 ${activeAgent.color.replace('text-', 'border-')}/40 ${activeAgent.color}` : 'bg-purple-500/10 border-purple-500/40 text-purple-400'}`}>
                  {viewMode === 'agents' ? <activeAgent.icon size={18} /> : <Database size={18} />}
                </div>
                <div className="max-w-[85%] w-full">
                   <div className="flex items-center gap-3 mb-1.5 px-1 font-black uppercase text-[8px] tracking-[0.2em] text-cyan-400">
                      IDENTIFYING SIGNAL...
                   </div>
                   <div className="glass-card p-4 text-sm text-white/80 border-cyan-500/20 ring-1 ring-cyan-500/10">
                      <ReactMarkdown remarkPlugins={[remarkGfm]}>{streaming}</ReactMarkdown>
                      <m.span animate={{ opacity: [0, 1, 0] }} transition={{ duration: 0.6, repeat: Infinity }} className="inline-block w-1.5 h-4 bg-cyan-400 ml-1 translate-y-0.5" />
                   </div>
                </div>
              </div>
            )}

            {loading && !streaming && (
               <div className="flex justify-center py-4" role="status" aria-label="Loading response">
                  <div className="flex items-center gap-4 px-5 py-2 rounded-full bg-white/5 border border-white/5 shadow-2xl">
                     <Loader2 size={14} className="animate-spin text-cyan-400" aria-hidden="true" />
                     <span className="text-[9px] font-black uppercase tracking-[0.3em] text-white/30">Calibrating Neural Weights...</span>
                  </div>
               </div>
            )}
            
            <div className="h-32 w-full shrink-0" /> {/* Spacer to prevent UI overlap with absolute input box */}
            <div ref={messagesEndRef} />
          </div>

          {/* Interactive Console HUD (Input) */}
          <div className="absolute bottom-6 inset-x-0 px-6 z-20 pointer-events-none">
            <div className="max-w-3xl mx-auto w-full pointer-events-auto">
               <div className="glass-card p-1.5 border-white/10 group focus-within:border-cyan-500/40 shadow-[0_32px_64px_-16px_rgba(0,0,0,0.5)] bg-[#0d0d14]/80 backdrop-blur-xl">
                  <div className="flex items-end gap-2 px-2">
                      <textarea
                      ref={inputRef}
                      value={input}
                      onChange={e => setInput(e.target.value)}
                      onKeyDown={e => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), sendMessage())}
                      placeholder={`TRANSMIT COMMAND TO ${viewMode === 'agents' ? activeAgent.name.toUpperCase() : 'ENGINE'}...`}
                      disabled={loading}
                      rows={1}
                      aria-label="Chat message input"
                      className="flex-1 bg-transparent text-white placeholder-white/10 text-sm outline-none resize-none py-3 font-medium tracking-tight min-h-[44px] max-h-32 overflow-y-auto"
                      style={{ fieldSizing: 'content' } as any}
                    />
                    <button
                      onClick={sendMessage}
                      disabled={!input.trim() || loading}
                      aria-label="Send message"
                      className={`w-10 h-10 rounded-xl flex items-center justify-center text-white shrink-0 transition-all shadow-xl mb-1 ${viewMode === 'models' ? 'bg-purple-600 hover:bg-purple-500 shadow-purple-500/20' : 'bg-cyan-600 hover:bg-cyan-500 shadow-cyan-500/20'} active:scale-95 disabled:opacity-20 disabled:grayscale`}
                    >
                      <Send size={18} aria-hidden="true" />
                    </button>
                  </div>
               </div>
               <div className="mt-3 flex justify-center">
                  <span className="text-[8px] font-black uppercase tracking-[0.5em] text-white/10">Neural Hub Bridge Alpha ΓÇó Secure Layer 4</span>
               </div>
            </div>
          </div>

        </main>
      </div>
    </PageLayout>
  );
}

import { useState, useEffect } from 'react';
import { HardDrive, Folder, FileText, ExternalLink, RefreshCw, ChevronRight, Home, Grid, List as ListIcon, Clock, ShieldAlert } from 'lucide-react';
import { m, AnimatePresence } from 'motion/react';
import type { DriveFile } from '../services/memoryService';
import PageLayout, { PageHeader, StatPill } from '../components/PageLayout';

export function Drive() {
  const [files, setFiles] = useState<DriveFile[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [breadcrumbs, setBreadcrumbs] = useState<{ id?: string; name: string }[]>([{ name: 'LuxRig_Brain' }]);
  const currentFolder = breadcrumbs[breadcrumbs.length - 1];

  const load = async (folderId?: string) => {
    setLoading(true); setError(null);
    try {
      const url = folderId ? `/api/drive/files?folderId=${folderId}` : '/api/drive/files';
      const res = await fetch(url);
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setFiles(data.files);
    } catch (e: any) { setError(e.message); } finally { setLoading(false); }
  };

  useEffect(() => { load(currentFolder.id); }, []);

  const navigateTo = (folder: DriveFile) => {
    const next = { id: folder.id, name: folder.name };
    setBreadcrumbs(b => [...b, next]);
    load(folder.id);
  };

  const navigateToBreadcrumb = (idx: number) => {
    const crumb = breadcrumbs[idx];
    setBreadcrumbs(b => b.slice(0, idx + 1));
    load(crumb.id);
  };

  const isFolder = (f: DriveFile) => f.mimeType === 'application/vnd.google-apps.folder';
  const formatDate = (s?: string) => s ? new Date(s).toLocaleDateString() : 'Unknown';

  return (
    <PageLayout color="cyan" noPadding>
      <div className="max-w-[2000px] mx-auto px-6 py-10 pb-32">
        <PageHeader
          title="Drive Explorer"
          subtitle="Manage your local and cloud-synced files."
          icon={<HardDrive size={24} className="text-cyan-400" />}
          actions={
            <div className="flex items-center gap-4">
              <div className="flex bg-white/5 border border-white/5 p-1 rounded-xl">
                <button 
                  onClick={() => setViewMode('grid')}
                  className={`p-2 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-white/10 text-white' : 'text-white/20 hover:text-white/40'}`}
                >
                  <Grid size={16} />
                </button>
                <button 
                  onClick={() => setViewMode('list')}
                  className={`p-2 rounded-lg transition-all ${viewMode === 'list' ? 'bg-white/10 text-white' : 'text-white/20 hover:text-white/40'}`}
                >
                  <ListIcon size={16} />
                </button>
              </div>
              <button 
                onClick={() => load(currentFolder.id)} 
                className={`w-10 h-10 flex items-center justify-center rounded-xl bg-white/5 border border-white/5 text-white/40 hover:text-white hover:bg-white/10 transition-all ${loading ? 'animate-pulse' : ''}`}
                title="Refresh"
              >
                <RefreshCw size={16} className={loading ? 'animate-spin text-cyan-500' : ''} />
              </button>
            </div>
          }
        />

        {/* Breadcrumbs Bar */}
        <div className="flex items-center gap-4 mb-10 overflow-x-auto no-scrollbar py-2">
           <nav className="flex items-center gap-1 bg-white/[0.03] border border-white/5 p-1.5 rounded-xl backdrop-blur-md">
              {breadcrumbs.map((crumb, i) => (
                <div key={i} className="flex items-center">
                  {i > 0 && <ChevronRight size={14} className="text-white/20 mx-1" />}
                  <button 
                    onClick={() => navigateToBreadcrumb(i)}
                    className={`text-xs font-bold tracking-wide transition-all px-4 py-2 rounded-lg border ${
                      i === breadcrumbs.length - 1 
                        ? 'text-cyan-400 bg-cyan-500/10 border-cyan-500/20 shadow-lg shadow-cyan-500/10' 
                        : 'text-white/40 border-transparent hover:text-white hover:bg-white/5'
                    }`}
                  >
                    {i === 0 ? <span className="flex items-center gap-2"><Home size={14} /> {crumb.name}</span> : crumb.name}
                  </button>
                </div>
              ))}
            </nav>
            <StatPill label={`${files.length} items`} color="cyan" />
        </div>

        {error && (
            <m.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="mb-8 p-5 rounded-2xl bg-red-500/10 border border-red-500/20 text-red-200 text-sm font-medium flex items-center gap-4">
                <ShieldAlert size={18} className="text-red-500" /> {error}
            </m.div>
        )}

        <AnimatePresence mode="wait">
          {loading ? (
            <m.div 
               key="loading"
               initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
               className="flex flex-col items-center justify-center py-40 gap-6 glass-card border flex-1"
            >
                <RefreshCw size={32} className="text-cyan-500 animate-spin opacity-50" />
                <span className="text-sm font-bold text-white/40 tracking-wider">Loading files...</span>
            </m.div>
          ) : files.length === 0 ? (
            <m.div 
                key="empty"
                initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
                className="glass-card border-dashed border-white/10 py-40 flex flex-col items-center justify-center text-center bg-white/[0.01]"
            >
                <div className="w-20 h-20 rounded-3xl bg-white/5 border border-white/10 flex items-center justify-center mb-8 text-white/20">
                    <Folder size={32} />
                </div>
                <h3 className="text-xl font-bold text-white mb-2">Folder is Empty</h3>
                <p className="text-sm text-white/40">Drop files here or check back later.</p>
            </m.div>
          ) : viewMode === 'grid' ? (
            <m.div 
                key="grid"
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6 gap-6"
            >
                {[...files].sort((a, b) => (isFolder(b) ? 1 : 0) - (isFolder(a) ? 1 : 0)).map((file, idx) => (
                    <m.div
                        key={file.id}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: idx * 0.02 }}
                        onClick={() => isFolder(file) ? navigateTo(file) : undefined}
                        className="group relative glass-card p-6 border-white/5 cursor-pointer hover:border-cyan-500/30 transition-all hover:bg-cyan-500/[0.02] flex flex-col items-center text-center bg-black/40 shadow-xl"
                    >
                        <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mb-6 transition-all group-hover:scale-110 ${isFolder(file) ? 'bg-cyan-500/10 text-cyan-400 border border-cyan-500/20' : 'bg-white/5 text-white/40 border border-white/5'}`}>
                           {isFolder(file) ? <Folder size={28} /> : <FileText size={28} />}
                        </div>
                        
                        <div className="w-full min-w-0">
                            <h3 className="text-sm font-bold text-white truncate mb-1.5 group-hover:text-cyan-400 transition-colors">{file.name}</h3>
                            <div className="flex items-center justify-center gap-2">
                                <span className="text-[10px] font-bold uppercase tracking-wider text-white/30">{isFolder(file) ? 'Folder' : (file.mimeType?.split('.').pop() || 'File').slice(0, 8)}</span>
                                <div className="w-1 h-1 rounded-full bg-white/10" />
                                <span className="text-[10px] font-medium text-white/30">{formatDate(file.modifiedTime)}</span>
                            </div>
                        </div>

                        <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-all scale-90 group-hover:scale-100">
                            {file.webViewLink && (
                                <a 
                                    href={file.webViewLink} target="_blank" rel="noopener noreferrer" onClick={e => e.stopPropagation()}
                                    className="p-2 bg-black/80 border border-white/10 rounded-lg text-white/50 hover:text-cyan-400 hover:bg-black transition-colors backdrop-blur-md"
                                >
                                    <ExternalLink size={14} />
                                </a>
                            )}
                        </div>
                    </m.div>
                ))}
            </m.div>
          ) : (
            <m.div 
                key="list"
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="glass-card border-white/5 overflow-hidden bg-black/40"
            >
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead>
                            <tr className="border-b border-white/5 bg-white/[0.02]">
                                <th className="px-8 py-5 text-[10px] font-bold uppercase tracking-wider text-white/40">Name</th>
                                <th className="px-8 py-5 text-[10px] font-bold uppercase tracking-wider text-white/40">Type</th>
                                <th className="px-8 py-5 text-[10px] font-bold uppercase tracking-wider text-white/40">Modified</th>
                                <th className="px-8 py-5 text-right"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {[...files].sort((a, b) => (isFolder(b) ? 1 : 0) - (isFolder(a) ? 1 : 0)).map((file) => (
                                <tr 
                                    key={file.id} 
                                    onClick={() => isFolder(file) ? navigateTo(file) : undefined}
                                    className={`group hover:bg-cyan-500/[0.02] transition-all cursor-pointer ${!isFolder(file) ? 'cursor-default' : ''}`}
                                >
                                    <td className="px-8 py-4">
                                        <div className="flex items-center gap-4">
                                            <div className={`p-2 rounded-lg transition-colors ${isFolder(file) ? 'bg-cyan-500/10 text-cyan-400 border border-cyan-500/20' : 'bg-white/5 text-white/40'}`}>
                                                {isFolder(file) ? <Folder size={16} /> : <FileText size={16} />}
                                            </div>
                                            <span className="text-sm font-bold text-white/80 group-hover:text-white">{file.name}</span>
                                        </div>
                                    </td>
                                    <td className="px-8 py-4">
                                        <span className="text-[11px] font-medium text-white/40">{isFolder(file) ? 'Folder' : file.mimeType?.split('/').pop()?.toUpperCase() || 'File'}</span>
                                    </td>
                                    <td className="px-8 py-4">
                                        <div className="flex items-center gap-3 text-white/40">
                                            <Clock size={12} />
                                            <span className="text-xs">{formatDate(file.modifiedTime)}</span>
                                        </div>
                                    </td>
                                    <td className="px-8 py-4 text-right">
                                        <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0">
                                            {file.webViewLink && (
                                                <a href={file.webViewLink} target="_blank" rel="noopener noreferrer" onClick={e => e.stopPropagation()} className="p-2 text-white/40 hover:text-cyan-400 bg-white/5 rounded-lg">
                                                    <ExternalLink size={14} />
                                                </a>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </m.div>
          )}
        </AnimatePresence>
      </div>
    </PageLayout>
  );
}

import { useState, useEffect } from 'react';
import { Plus, Save, Clock, RefreshCw, Music, Edit3 } from 'lucide-react';
import { m, AnimatePresence } from 'motion/react';
import { useToast } from '../contexts/ToastContext';
import PageLayout, { StatPill } from '../components/PageLayout';
import { io } from 'socket.io-client';
import PipelineFlow from '../components/pipeline/PipelineFlow';

