const STATUS_CONFIG = {
  planning: { color: 'text-zinc-400', bg: 'bg-zinc-400/10', border: 'border-zinc-400/20', label: 'PLANNING' },
  production: { color: 'text-purple-400', bg: 'bg-purple-400/10', border: 'border-purple-400/20', label: 'PRODUCTION' },
  mixing: { color: 'text-cyan-400', bg: 'bg-cyan-400/10', border: 'border-cyan-400/20', label: 'MIXING' },
  mastering: { color: 'text-blue-400', bg: 'bg-blue-400/10', border: 'border-blue-400/20', label: 'MASTERING' },
  release: { color: 'text-amber-400', bg: 'bg-amber-400/10', border: 'border-amber-400/20', label: 'RELEASE' },
  done: { color: 'text-emerald-400', bg: 'bg-emerald-400/10', border: 'border-emerald-400/20', label: 'FINALIZED' },
};

const DEFAULT_STEPS = [
  { name: 'Concept & Lyrics', status: 'pending' },
  { name: 'Beat Selection', status: 'pending' },
  { name: 'Vocal Tracking', status: 'pending' },
  { name: 'Rough Mix', status: 'pending' },
  { name: 'Final Mix', status: 'pending' },
  { name: 'Mastering', status: 'pending' },
  { name: 'Cover Art', status: 'pending' },
  { name: 'Distribution', status: 'pending' }
];

export function Pipeline() {
  const [tracks, setTracks] = useState<PipelineTrack[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrack, setSelectedTrack] = useState<PipelineTrack | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [isCreating, setIsCreating] = useState(false);
  const [editForm, setEditForm] = useState<Partial<PipelineTrack>>({});
  const [syncing, setSyncing] = useState(false);
  const { toast } = useToast();

  const fetchTracks = async () => {
    try {
      const res = await fetch(`${import.meta.env.VITE_API_URL || ''}/api/pipeline`);
      if (res.ok) {
        const contentType = res.headers.get('content-type');
        if (contentType && contentType.includes('application/json')) {
          const data = await res.json();
          setTracks(data);
          if (data.length > 0 && !selectedTrack && !isCreating) {
            setSelectedTrack(data[0]);
          }
        } else {
          setTracks([]);
        }
      } else {
        setTracks([]);
      }
    } catch (err) {
      console.error('Pipeline fetch error:', err);
      setTracks([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTracks();

    // Phase 6: Subscribing to Socket.IO events for live UI updates
    const LOCAL_BACKEND = (window as any).NEXUS_API_BASE || '';
    const socket = io(LOCAL_BACKEND, {
      transports: ['websocket'], // Force websockets to prevent Cloud Run load balancer from breaking the polling handshake
    }); // Connects dynamically (Tauri uses port 3001, normal web uses relative origin)

    socket.on('pipeline_update', () => {
      // When the backend or an autonomous agent updates a track, automatically refresh the list
      fetchTracks();
    });

    return () => {
      socket.disconnect();
    };
  }, []);

  const handleSave = async () => {
    if (isCreating) {
      const id = editForm.title?.toLowerCase().replace(/[^a-z0-9]/g, '-') + '-' + Date.now();
      const newTrack = {
        id,
        artist: editForm.artist || 'Unknown Artist',
        title: editForm.title || 'Untitled',
        status: (editForm.status as any) || 'planning',
        progress: editForm.progress || 0,
        steps: editForm.steps || JSON.stringify(DEFAULT_STEPS),
        target_date: editForm.target_date || new Date().toISOString().split('T')[0]
      };
      const res = await fetch(`${import.meta.env.VITE_API_URL || ''}/api/pipeline`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTrack),
      });
      if (res.ok) {
        const saved = await res.json();
        setTracks(prev => [...prev, saved]);
        setSelectedTrack(saved);
        setIsCreating(false);
        setIsEditing(false);
        toast.success(`"${newTrack.title}" added to pipeline`);
      } else {
        toast.error('Failed to create track');
      }
    } else if (selectedTrack) {
      const updatedTrack = { ...selectedTrack, ...editForm };
      const res = await fetch(`${import.meta.env.VITE_API_URL || ''}/api/pipeline/${selectedTrack.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(updatedTrack),
      });
      if (res.ok) {
        setTracks(prev => prev.map(t => t.id === updatedTrack.id ? updatedTrack : t));
        setSelectedTrack(updatedTrack as any);
        setIsEditing(false);
        toast.success('Track saved');
        fetchTracks();
      } else {
        toast.error('Failed to save track');
      }
    }
  };

  const updateStepStatus = async (stepIndex: number, newStatus: PipelineStep['status']) => {
    if (!selectedTrack) return;
    try {
      const steps: PipelineStep[] = JSON.parse(selectedTrack.steps || '[]');
      if (steps[stepIndex]) {
        steps[stepIndex].status = newStatus;
        
        const completed = steps.filter(s => s.status === 'completed').length;
        const progress = Math.round((completed / steps.length) * 100);

        const updatedTrack = { ...selectedTrack, steps: JSON.stringify(steps), progress };
        
        const res = await fetch(`${import.meta.env.VITE_API_URL || ''}/api/pipeline/${selectedTrack.id}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(updatedTrack),
        });
        
        if (res.ok) {
           setSelectedTrack(updatedTrack as any);
           setTracks(prev => prev.map(t => t.id === updatedTrack.id ? updatedTrack : (t as any)));
        }
      }
    } catch (e) { console.error(e); }
  };

  const handleSync = async () => {
    setSyncing(true);
    toast.info('Syncing PipelineΓÇª');
    try {
      const res = await fetch(`${import.meta.env.VITE_API_URL || ''}/api/pipeline/sync`, { method: 'POST' });
      if (res.ok) {
        const data = await res.json();
        if (data.success && data.tracks) {
           setTracks(data.tracks);
           if (selectedTrack) {
             const updatedCurrent = data.tracks.find((t: PipelineTrack) => t.id === selectedTrack.id);
             if (updatedCurrent) setSelectedTrack(updatedCurrent);
           }
           toast.success('Pipeline Synchronized');
        }
      } else {
        const err = await res.json();
        toast.error('Sync failed: ' + err.error);
      }
    } catch (e) {
        toast.error('Sync failed ΓÇö server unreachable');
    } finally {
      setSyncing(false);
    }
  };

  const parsedSteps: PipelineStep[] = selectedTrack?.steps ? JSON.parse(selectedTrack.steps) : [];

  if (loading) return (
    <div className="flex h-full min-h-[500px] items-center justify-center">
      <div className="animate-spin rounded-full h-10 w-10 border-2 border-purple-500 border-t-transparent shadow-[0_0_20px_rgba(168,85,247,0.3)]" />
    </div>
  );

  return (
    <PageLayout color="purple" noPadding>
      <div className="flex flex-col md:flex-row h-[calc(100vh-64px)] relative overflow-hidden">

        {/* Sidebar: Pipeline Stack */}
        <aside className="w-full md:w-80 border-b md:border-b-0 md:border-r border-white/5 bg-black/40 backdrop-blur-xl flex flex-col shrink-0 relative z-20 shadow-2xl max-h-64 md:max-h-none overflow-y-auto md:overflow-visible">
          <div className="p-8 border-b border-white/5 bg-gradient-to-br from-purple-500/5 to-transparent flex items-center justify-between">
            <div>
              <h2 className="text-[10px] uppercase font-black tracking-[0.4em] text-purple-400 mb-2">Active Projects</h2>
              <span className="text-xl font-black text-white tracking-tighter uppercase">Pipeline</span>
            </div>
            <button
                onClick={handleSync} 
                disabled={syncing} 
                className="w-10 h-10 flex items-center justify-center rounded-xl bg-white/5 border border-white/10 text-white/30 hover:text-white transition-all group"
                title="Sync with GSheets"
            >
                <RefreshCw size={16} className={syncing ? 'animate-spin text-purple-500' : 'group-hover:rotate-180 transition-transform duration-500'} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-1">
            {tracks.length === 0 && (
              <div className="flex flex-col items-center justify-center h-40 text-center px-4">
                <div className="text-[8px] font-black text-white/20 uppercase tracking-[0.3em] mb-2">NO TRACKS</div>
                <div className="text-[9px] text-white/30">Add your first release to the pipeline.</div>
              </div>
            )}
            {tracks.map((track, idx) => {
              const statusInfo = STATUS_CONFIG[track.status as keyof typeof STATUS_CONFIG] || STATUS_CONFIG.planning;
              return (
                <m.div
                  key={track.id}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: idx * 0.05 }}
                  onClick={() => { setSelectedTrack(track); setIsCreating(false); setIsEditing(false); setEditForm(track); }}
                  className={`group px-4 py-4 rounded-xl cursor-pointer transition-all border relative ${selectedTrack?.id === track.id && !isCreating 
                    ? 'bg-purple-500/10 border-purple-500/30 text-white shadow-xl shadow-purple-950/20' 
                    : 'text-white/40 border-transparent hover:bg-white/[0.03] hover:text-white'}`}
                >
                  {selectedTrack?.id === track.id && !isCreating && (
                    <m.div layoutId="pipeline-active-marker" className="absolute left-1.5 top-4 bottom-4 w-0.5 bg-purple-500 rounded-full" />
                  )}
                  <div className="flex justify-between items-start mb-3">
                    <div className="min-w-0 flex-1">
                      <div className="text-xs font-black truncate uppercase tracking-tight">{track.title}</div>
                      <div className="text-[8px] font-black uppercase tracking-widest opacity-30 mt-1">{track.artist}</div>
                    </div>
                    <div className={`w-1.5 h-1.5 rounded-full ${statusInfo.color.replace('text-', 'bg-')} shadow-[0_0_8px_currentColor]`} />
                  </div>
                  <div className="flex items-center gap-3 mt-4">
                    <div className="flex-1 h-0.5 bg-white/5 rounded-full overflow-hidden">
                       <m.div initial={{ width: 0 }} animate={{ width: `${track.progress}%` }} className="h-full bg-purple-500" />
                    </div>
                    <span className="text-[8px] font-black text-white/20 font-mono tracking-tighter">{track.progress}%</span>
                  </div>
                </m.div>
              );
            })}
            
            <button
               onClick={() => { setSelectedTrack(null); setIsCreating(true); setIsEditing(true); setEditForm({ status: 'planning', progress: 0, steps: JSON.stringify(DEFAULT_STEPS) }); }}
               className="w-full mt-4 p-4 rounded-xl border border-dashed border-white/10 text-white/20 hover:text-white/50 hover:border-white/20 hover:bg-white/[0.02] transition-all flex items-center justify-center gap-3"
            >
               <Plus size={16} />
               <span className="text-[10px] font-black uppercase tracking-[0.2em]">New Track</span>
            </button>
          </div>
        </aside>

        {/* Primary Operational View */}
        <main className="flex-1 overflow-y-auto custom-scrollbar relative z-10 bg-black/20">
          <div className="max-w-4xl mx-auto px-8 py-10 pb-40">
            <AnimatePresence mode="wait">
              {(selectedTrack || isCreating) ? (
                <m.div key={isCreating ? 'create' : selectedTrack?.id} initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -30 }} className="space-y-10">
                  
                  {/* Status Header Panel */}
                  <div className="glass-card border-white/5 bg-white/[0.01] p-8 relative overflow-hidden group">
                     <div className="absolute top-0 right-0 w-80 h-80 bg-purple-500/5 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2" />
                     <div className="relative z-10 flex flex-col md:flex-row items-start justify-between gap-6">
                        <div className="flex-1 min-w-0">
                           {isEditing ? (
                             <div className="space-y-6 w-full">
                                <div className="space-y-1">
                                   <label className="text-[9px] font-black text-white/10 uppercase tracking-[0.3em]">Track Title</label>
                                   <input type="text" value={editForm.title || ''} onChange={e => setEditForm(p => ({ ...p, title: e.target.value }))}
                                      className="text-4xl font-black text-white bg-transparent border-0 focus:ring-0 w-full p-0 tracking-tighter uppercase placeholder:text-white/5" />
                                </div>
                                <div className="space-y-1">
                                   <label className="text-[9px] font-black text-white/10 uppercase tracking-[0.3em]">Artist</label>
                                   <input type="text" value={editForm.artist || ''} onChange={e => setEditForm(p => ({ ...p, artist: e.target.value }))}
                                      className="text-lg font-black text-white/40 bg-transparent border-0 focus:ring-0 w-full p-0 tracking-[0.2em] uppercase placeholder:text-white/5" />
                                </div>
                                <div className="flex flex-wrap gap-4 pt-4">
                                   <div className="space-y-2">
                                      <label className="text-[9px] font-black text-white/10 uppercase tracking-[0.3em]">Status</label>
                                      <select value={editForm.status || 'planning'} onChange={e => setEditForm(p => ({ ...p, status: e.target.value as any }))}
                                         className="bg-white/5 border border-white/10 rounded-lg px-4 py-2 text-[10px] font-black uppercase text-purple-400 outline-none">
                                         {Object.keys(STATUS_CONFIG).map(s => <option key={s} value={s}>{s.toUpperCase()}</option>)}
                                      </select>
                                   </div>
                                   <div className="space-y-2">
                                      <label className="text-[9px] font-black text-white/10 uppercase tracking-[0.3em]">Target Date</label>
                                      <input type="date" value={editForm.target_date || ''} onChange={e => setEditForm(p => ({ ...p, target_date: e.target.value }))}
                                         className="bg-white/5 border border-white/10 rounded-lg px-4 py-2 text-[10px] font-black text-white outline-none" style={{ colorScheme: 'dark' }} />
                                   </div>
                                </div>
                             </div>
                           ) : (
                             <div className="space-y-6">
                                <div className="flex gap-2">
                                  <StatPill label={STATUS_CONFIG[selectedTrack?.status as keyof typeof STATUS_CONFIG]?.label || ''} color="purple" pulse />
                                  <StatPill label={`STK-${(selectedTrack?.id || '').slice(0, 5).toUpperCase()}`} />
                                </div>
                                <h1 className="text-5xl font-black text-white uppercase tracking-tighter leading-none">{selectedTrack?.title}</h1>
                                <p className="text-xl font-black text-white/20 uppercase tracking-[0.4em]">{selectedTrack?.artist}</p>
                                <div className="flex items-center gap-4 pt-2">
                                   <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-white/20 bg-black/40 px-3 py-2 rounded-xl border border-white/5">
                                      <Clock size={12} className="text-purple-500" />
                                      {selectedTrack?.target_date ? `Deadline: ${new Date(selectedTrack.target_date).toLocaleDateString()}` : 'No Deadline Established'}
                                   </div>
                                </div>
                             </div>
                           )}
                        </div>

                        <div className="flex gap-3">
                           {isEditing ? (
                             <>
                               <button onClick={() => { setIsEditing(false); if (isCreating) { setIsCreating(false); if (tracks.length) setSelectedTrack(tracks[0]); } }}
                                 className="px-6 py-2.5 rounded-xl bg-white/5 border border-white/10 text-white/30 text-[10px] font-black uppercase tracking-widest hover:text-white transition-all">Discard</button>
                               <button onClick={handleSave}
                                 className="px-6 py-2.5 rounded-xl bg-purple-600 text-white text-[10px] font-black uppercase tracking-widest hover:bg-purple-500 transition-all shadow-xl shadow-purple-500/20 flex items-center gap-2">
                                 <Save size={14} /> Commit
                               </button>
                             </>
                           ) : (
                             <button onClick={() => { setIsEditing(true); setEditForm(selectedTrack!); }}
                               className="px-6 py-2.5 rounded-xl bg-white/5 border border-white/10 text-white/50 text-[10px] font-black uppercase tracking-widest hover:text-white hover:bg-white/10 transition-all flex items-center gap-2">
                               <Edit3 size={14} /> Edit Properties
                             </button>
                           )}
                        </div>
                     </div>
                  </div>

                  {/* Operational Matrix / Steps */}
                  {!isCreating && (
                    <div className="space-y-8">
                       <div className="flex items-center justify-between px-2">
                          <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-white/20 flex items-center gap-4">
                            <div className="w-1.5 h-1.5 bg-purple-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(168,85,247,0.5)]" />
                            Production Steps
                          </h3>
                          <div className="flex items-center gap-4">
                             <span className="text-[9px] font-black uppercase tracking-widest text-white/20">Progress</span>
                             <div className="flex items-center gap-3">
                                <div className="w-40 h-1.5 bg-white/5 rounded-full overflow-hidden">
                                   <m.div initial={{ width: 0 }} animate={{ width: `${selectedTrack?.progress}%` }} className="h-full bg-purple-500 shadow-[0_0_10px_rgba(168,85,247,0.3)]" />
                                </div>
                                <span className="text-[11px] font-black text-purple-400 font-mono">{selectedTrack?.progress}%</span>
                             </div>
                          </div>
                       </div>

                       <div className="mt-8 rounded-3xl overflow-hidden glass-card shadow-2xl shadow-purple-900/10">
                          <PipelineFlow
                            steps={parsedSteps as any}
                            onUpdateStep={updateStepStatus}
                          />
                       </div>
                    </div>
                  )}

                </m.div>
              ) : (
                <div className="h-[60vh] flex flex-col items-center justify-center text-center p-12">
                   <div className="w-16 h-16 rounded-3xl bg-white/5 border border-white/5 flex items-center justify-center mb-6 shadow-2xl relative group cursor-pointer" 
                        onClick={() => { setSelectedTrack(null); setIsCreating(true); setIsEditing(true); setEditForm({ status: 'planning', progress: 0, steps: JSON.stringify(DEFAULT_STEPS) }); }}>
                      <Music className="w-8 h-8 text-white/10 group-hover:text-purple-400 transition-all" />
                      <div className="absolute inset-0 bg-purple-500/10 blur-2xl rounded-full opacity-0 group-hover:opacity-100 transition-all" />
                   </div>
                   <h3 className="text-xl font-black text-white/20 uppercase tracking-widest">No Track Selected</h3>
                   <p className="text-[10px] text-white/10 mt-2 max-w-xs uppercase font-black tracking-[0.2em] leading-loose">
                      Select a track from the pipeline stack or initialize a new project
                   </p>
                </div>
              )}
            </AnimatePresence>
          </div>
        </main>
      </div>
    </PageLayout>
  );
}

import React, { useMemo } from 'react';
import { usePortfolio } from '@/contexts/labs/smartfolio/PortfolioContext';
import { ACCOUNTS, type AccountId, LOGO_MAPPING, type Asset } from '@/lib/smartfolio/store/portfolio';
import { STRATEGIES } from '@/lib/smartfolio/store/strategy';
import PriceTicker from '@/components/labs/smartfolio/PriceTicker';

const currency = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2 });

// ΓöÇΓöÇΓöÇ Sparkline ΓöÇΓöÇΓöÇ
function Sparkline({ data, color }: { data: number[]; color: string }) {
    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;
    const width = 100;
    const height = 20;
    const points = data.map((d, i) => ({
        x: (i / (data.length - 1)) * width,
        y: height - ((d - min) / range) * height,
    }));
    const path = `M ${points.map(p => `${p.x},${p.y}`).join(' L ')}`;
    return (
        <svg width={width} height={height} className="overflow-visible">
            <path d={path} fill="none" stroke={color === 'red' ? '#fb7185' : '#10b981'} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
            <path d={`${path} L ${width},${height} L 0,${height} Z`} fill={`url(#grad-aum-${color})`} opacity="0.1" />
            <defs>
                <linearGradient id={`grad-aum-${color}`} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={color === 'red' ? '#fb7185' : '#10b981'} />
                    <stop offset="100%" stopColor="transparent" />
                </linearGradient>
            </defs>
        </svg>
    );
}

function Metric({ label, value, color, trend, chart }: { label: string; value: string | number; color?: string; trend?: string; chart?: React.ReactNode }) {
    return (
        <div className="flex flex-col gap-1 p-5 rounded-xl border border-white/5 bg-gradient-to-br from-white/10 to-transparent hover:from-white/15 transition-all duration-300 relative overflow-hidden group">
            <div className={`absolute -right-6 -top-6 w-24 h-24 rounded-full blur-2xl opacity-10 group-hover:opacity-20 transition-opacity ${color?.includes('green') || color?.includes('emerald') ? 'bg-green-500' : color?.includes('red') || color?.includes('rose') ? 'bg-red-500' : 'bg-blue-500'}`}></div>
            <span className="text-gray-400 text-[10px] uppercase tracking-widest font-semibold flex justify-between items-center z-10">
                {label}
                {trend && <span className={`text-[10px] ${trend.startsWith('+') ? 'text-green-400' : trend.startsWith('ΓÜá') ? 'text-rose-400' : 'text-gray-400'}`}>{trend}</span>}
            </span>
            <div className="flex items-end justify-between z-10">
                <span className={`text-2xl font-mono font-bold tracking-tight ${color || 'text-white'}`}>{value}</span>
                {chart}
            </div>
            {!chart && (
                <div className="h-1 w-full bg-white/5 mt-2 rounded overflow-hidden">
                    <div className={`h-full w-2/3 ${color?.includes('red') || color?.includes('rose') ? 'bg-red-500' : 'bg-emerald-500'} opacity-50`}></div>
                </div>
            )}
        </div>
    );
}

export function SmartFolioAUM() {
    const [mounted, setMounted] = React.useState(false);
    const [syncTime, setSyncTime] = React.useState('');
    const { assets, activeAccount, pendingOrders } = usePortfolio();

    React.useEffect(() => {
        setMounted(true);
        setSyncTime(new Date().toLocaleTimeString());
    }, []);

    // ΓöÇΓöÇΓöÇ Merge both accounts ΓöÇΓöÇΓöÇ
    const otherAccountId: AccountId = activeAccount === 'sui' ? 'alts' : 'sui';
    const otherAssets = ACCOUNTS[otherAccountId].assets;

    const activeTotal = assets.reduce((s, a) => s + a.currentValue, 0);
    const otherTotal = otherAssets.reduce((s, a) => s + a.currentValue, 0);
    const combinedTotal = activeTotal + otherTotal;

    // Combine positions ΓÇö merge same symbols across accounts
    const mergedPositions = useMemo(() => {
        const map = new Map<string, {
            symbol: string;
            currentValue: number;
            currentPrice: number;
            totalCost: number;
            gainLoss: number;
            units: number;
            accounts: string[];
        }>();

        const process = (assetList: Asset[], acctLabel: string) => {
            assetList.forEach(a => {
                const existing = map.get(a.symbol);
                if (existing) {
                    existing.currentValue += a.currentValue;
                    existing.totalCost += (a.totalCost || 0);
                    existing.gainLoss += (a.gainLoss || 0);
                    existing.units += a.units;
                    if (!existing.accounts.includes(acctLabel)) existing.accounts.push(acctLabel);
                } else {
                    map.set(a.symbol, {
                        symbol: a.symbol,
                        currentValue: a.currentValue,
                        currentPrice: a.currentPrice,
                        totalCost: a.totalCost || 0,
                        gainLoss: a.gainLoss || 0,
                        units: a.units,
                        accounts: [acctLabel],
                    });
                }
            });
        };

        process(assets, activeAccount === 'sui' ? 'SUI' : 'ALTS');
        process(otherAssets, otherAccountId === 'sui' ? 'SUI' : 'ALTS');

        return [...map.values()]
            .map(p => ({ ...p, allocation: (p.currentValue / combinedTotal) * 100 }))
            .sort((a, b) => b.currentValue - a.currentValue);
    }, [assets, otherAssets, combinedTotal, activeAccount, otherAccountId]);

    const totalCash = mergedPositions.find(p => p.symbol === 'USD')?.currentValue || 0;
    const cashPercent = (totalCash / combinedTotal) * 100;
    const totalGainLoss = mergedPositions.filter(p => p.symbol !== 'USD').reduce((s, p) => s + p.gainLoss, 0);
    const totalCost = mergedPositions.filter(p => p.symbol !== 'USD').reduce((s, p) => s + p.totalCost, 0);
    const pnlPercent = totalCost > 0 ? ((totalGainLoss / totalCost) * 100) : 0;
    const coins = mergedPositions.filter(p => p.symbol !== 'USD');
    const positionCount = coins.length;
    const largestPosition = coins[0];

    // Pending orders across both accounts
    const allPendingOrders = useMemo(() => {
        const activeOrders = pendingOrders.map(o => ({ ...o, account: activeAccount }));
        const otherOrders = ACCOUNTS[otherAccountId].pendingOrders.map(o => ({ ...o, account: otherAccountId }));

        // De-dupe by ID (priority to active account)
        const combined = [...activeOrders, ...otherOrders];
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const uniqueMap = new Map<string, any>();
        combined.forEach(o => {
            if (!uniqueMap.has(o.id)) uniqueMap.set(o.id, o);
        });

        return Array.from(uniqueMap.values());
    }, [pendingOrders, activeAccount, otherAccountId]);

    const totalStagedValue = allPendingOrders.reduce((s, o) => s + o.units * o.price, 0);

    if (!mounted) return null;

    return (
        <>
            {/* Dynamic Background Effect */}
            <div className="fixed inset-0 pointer-events-none opacity-20 z-0 text-white">
                <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-900/40 blur-[150px] rounded-full animate-pulse"></div>
                <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-blue-900/30 blur-[150px] rounded-full animate-pulse delay-1000"></div>
            </div>

            <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-xl flex items-center justify-between px-6 z-30 sticky top-0">
                <div className="flex items-center gap-2 lg:gap-4 flex-wrap">
                    <span className="text-lg">≡ƒÆ░</span>
                    <h1 className="text-sm font-black text-white uppercase tracking-widest">Combined AUM</h1>
                    <div className="h-4 w-px bg-white/10 mx-2"></div>
                    <span className="text-[10px] font-mono text-purple-400 bg-purple-500/10 px-2 py-0.5 rounded border border-purple-500/20">CROSS-ACCOUNT VIEW</span>
                    <div className="h-4 w-px bg-white/10 mx-2"></div>
                    <span className="text-[10px] font-mono text-gray-500 tracking-tighter lowercase opacity-50">
                        last_sync: {syncTime}
                    </span>
                </div>
                <div className="flex items-center gap-6">
                    <div className="hidden lg:flex items-center gap-3 px-3 py-1.5 rounded-lg bg-white/5 border border-white/10">
                        <span className="text-[10px] text-blue-400 font-black tracking-widest uppercase">2 Roth IRAs</span>
                        <span className="text-[11px] font-mono text-gray-400">Tax-Free Gains</span>
                    </div>
                </div>
            </header>

            <div className="flex-1 overflow-y-auto p-6 pb-20 relative z-10 scroll-smooth custom-scrollbar">
              <div className="max-w-[2000px] mx-auto space-y-6">
                {/* ΓòÉΓòÉΓòÉ TOP METRICS ROW ΓòÉΓòÉΓòÉ */}
                <section className="animate-fade-in-up">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                        <Metric
                            label="Combined AUM"
                            value={currency.format(combinedTotal)}
                            color="text-white"
                            chart={<Sparkline data={[combinedTotal - 200, combinedTotal - 100, combinedTotal - 150, combinedTotal - 50, combinedTotal]} color="green" />}
                        />
                        <Metric
                            label="Combined PnL"
                            value={currency.format(totalGainLoss)}
                            color={totalGainLoss >= 0 ? 'text-emerald-400' : 'text-rose-400'}
                            trend={`${pnlPercent >= 0 ? '+' : ''}${pnlPercent.toFixed(2)}% ROI`}
                        />
                        <Metric
                            label="Total Positions"
                            value={`${positionCount} Coins`}
                            color="text-blue-400"
                            trend={largestPosition ? `Largest: ${largestPosition.symbol} @ ${largestPosition.allocation.toFixed(1)}%` : ''}
                        />
                        <Metric
                            label="Combined Cash"
                            value={currency.format(totalCash)}
                            color={cashPercent < 10 ? 'text-rose-400' : cashPercent < 20 ? 'text-amber-400' : 'text-emerald-400'}
                            trend={`${cashPercent.toFixed(1)}% of AUM`}
                        />
                        <Metric
                            label="Staged Orders"
                            value={`${allPendingOrders.length} Orders`}
                            color="text-purple-400"
                            trend={totalStagedValue > 0 ? `${currency.format(totalStagedValue)} value` : 'No orders staged'}
                        />
                    </div>
                </section>

                {/* Global Market Pulse */}
                <section className="animate-fade-in-up delay-75">
                    <PriceTicker />
                </section>

                {/* ΓòÉΓòÉΓòÉ ACCOUNT BREAKDOWN ΓòÉΓòÉΓòÉ */}
                <section className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in-up delay-100">
                    {([activeAccount, otherAccountId] as AccountId[])
                        .sort((a, b) => {
                            const valA = a === activeAccount ? activeTotal : otherTotal;
                            const valB = b === activeAccount ? activeTotal : otherTotal;
                            return valB - valA;
                        })
                        .map(accId => {
                            const acctAssets = accId === activeAccount ? assets : otherAssets;
                            const acctTotal = accId === activeAccount ? activeTotal : otherTotal;
                            const acctStrategy = STRATEGIES[accId];
                            const acctCoins = acctAssets.filter(a => a.symbol !== 'USD');
                            const acctCash = acctAssets.find(a => a.symbol === 'USD')?.currentValue || 0;
                            const acctCashPct = (acctCash / acctTotal) * 100;
                            const acctGainLoss = acctCoins.reduce((s, a) => s + (a.gainLoss || 0), 0);
                            const isActive = accId === activeAccount;
                            return (
                                <div key={accId} className={`glass-card p-6 space-y-4 ${isActive ? 'border-l-4 border-l-blue-500/50' : 'border-l-4 border-l-white/10'}`}>
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            <span className="text-lg">{accId === 'sui' ? '≡ƒææ' : '≡ƒöä'}</span>
                                            <div>
                                                <h3 className="text-sm font-black text-white">{ACCOUNTS[accId].accountName}</h3>
                                                <span className="text-[9px] text-gray-500 font-mono">{acctStrategy.name} ΓÇó {ACCOUNTS[accId].accountNumber}</span>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <div className="text-lg font-black font-mono text-white">{currency.format(acctTotal)}</div>
                                            <span className="text-[9px] text-gray-500 font-mono">{((acctTotal / combinedTotal) * 100).toFixed(1)}% of AUM</span>
                                        </div>
                                    </div>

                                    {/* Mini stats */}
                                    <div className="grid grid-cols-3 gap-3">
                                        <div className="p-3 rounded-xl bg-white/[0.02] border border-white/5">
                                            <span className="text-[8px] text-gray-600 uppercase tracking-wider">PnL</span>
                                            <div className={`text-sm font-black font-mono ${acctGainLoss >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                                {acctGainLoss >= 0 ? '+' : ''}{currency.format(acctGainLoss)}
                                            </div>
                                        </div>
                                        <div className="p-3 rounded-xl bg-white/[0.02] border border-white/5">
                                            <span className="text-[8px] text-gray-600 uppercase tracking-wider">Cash</span>
                                            <div className={`text-sm font-black font-mono ${acctCashPct < 10 ? 'text-rose-400' : 'text-white'}`}>
                                                {acctCashPct.toFixed(1)}%
                                            </div>
                                        </div>
                                        <div className="p-3 rounded-xl bg-white/[0.02] border border-white/5">
                                            <span className="text-[8px] text-gray-600 uppercase tracking-wider">Positions</span>
                                            <div className="text-sm font-black font-mono text-white">{acctCoins.length}</div>
                                        </div>
                                    </div>

                                    {/* Top holdings */}
                                    <div className="space-y-1.5">
                                        {acctCoins.sort((a, b) => b.currentValue - a.currentValue).slice(0, 5).map(a => (
                                            <div key={a.symbol} className="flex items-center justify-between py-1.5 px-2 rounded-lg hover:bg-white/[0.03] transition-all">
                                                <div className="flex items-center gap-2">
                                                    {LOGO_MAPPING[a.symbol] && <img src={LOGO_MAPPING[a.symbol]} alt="" className="w-4 h-4" />}
                                                    <span className="text-[11px] font-bold text-white">{a.symbol}</span>
                                                    <span className="text-[9px] text-gray-600 font-mono">{a.allocation.toFixed(1)}%</span>
                                                </div>
                                                <div className="flex items-center gap-3">
                                                    <span className={`text-[10px] font-mono ${(a.gainLoss || 0) >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                                        {(a.gainLoss || 0) >= 0 ? '+' : ''}{currency.format(a.gainLoss || 0)}
                                                    </span>
                                                    <span className="text-[10px] font-mono text-white font-bold">{currency.format(a.currentValue)}</span>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            );
                        })}
                </section>

                {/* ΓòÉΓòÉΓòÉ MERGED POSITIONS LEDGER ΓòÉΓòÉΓòÉ */}
                <section className="glass-card p-0 overflow-hidden animate-fade-in-up delay-150">
                    <div className="p-6 pb-3 flex items-center justify-between border-b border-white/5">
                        <div className="flex items-center gap-3">
                            <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">All Positions (Merged)</h3>
                            <span className="text-[9px] text-gray-600 font-mono bg-white/5 px-2 py-0.5 rounded border border-white/10">
                                {coins.length} unique assets across 2 accounts
                            </span>
                        </div>
                    </div>

                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="border-b border-white/5">
                                    <th className="p-4 text-[9px] font-bold text-gray-500 uppercase tracking-widest">Asset</th>
                                    <th className="p-4 text-[9px] font-bold text-gray-500 uppercase tracking-widest">Accounts</th>
                                    <th className="p-4 text-[9px] font-bold text-gray-500 uppercase tracking-widest text-right">Units</th>
                                    <th className="p-4 text-[9px] font-bold text-gray-500 uppercase tracking-widest text-right">Spot Price</th>
                                    <th className="p-4 text-[9px] font-bold text-gray-500 uppercase tracking-widest text-right">Value</th>
                                    <th className="p-4 text-[9px] font-bold text-gray-500 uppercase tracking-widest text-right">Alloc</th>
                                    <th className="p-4 text-[9px] font-bold text-gray-500 uppercase tracking-widest text-right">Cost</th>
                                    <th className="p-4 text-[9px] font-bold text-gray-500 uppercase tracking-widest text-right">PnL</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                                {coins.map(p => {
                                    const roi = p.totalCost > 0 ? ((p.gainLoss / p.totalCost) * 100) : 0;
                                    return (
                                        <tr key={p.symbol} className="hover:bg-white/[0.03] transition-all">
                                            <td className="p-4">
                                                <div className="flex items-center gap-2.5">
                                                    {LOGO_MAPPING[p.symbol] && <img src={LOGO_MAPPING[p.symbol]} alt="" className="w-5 h-5" />}
                                                    <span className="text-sm font-black text-white">{p.symbol}</span>
                                                </div>
                                            </td>
                                            <td className="p-4">
                                                <div className="flex items-center gap-1">
                                                    {p.accounts.map(a => (
                                                        <span key={a} className={`text-[8px] font-bold px-1.5 py-0.5 rounded border ${a === 'SUI' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' : 'bg-purple-500/10 text-purple-400 border-purple-500/20'}`}>
                                                            {a}
                                                        </span>
                                                    ))}
                                                </div>
                                            </td>
                                            <td className="p-4 text-right text-xs font-mono text-gray-300">{p.units.toLocaleString(undefined, { maximumFractionDigits: 2 })}</td>
                                            <td className="p-4 text-right text-xs font-mono text-blue-400">{currency.format(p.currentPrice)}</td>
                                            <td className="p-4 text-right text-xs font-mono text-white font-bold">{currency.format(p.currentValue)}</td>
                                            <td className="p-4 text-right">
                                                <div className="flex items-center justify-end gap-2">
                                                    <div className="w-16 h-1.5 bg-white/5 rounded-full overflow-hidden">
                                                        <div className="h-full bg-blue-500/60 rounded-full" style={{ width: `${Math.min(p.allocation, 100)}%` }}></div>
                                                    </div>
                                                    <span className="text-xs font-mono text-gray-400 w-12 text-right">{p.allocation.toFixed(1)}%</span>
                                                </div>
                                            </td>
                                            <td className="p-4 text-right text-xs font-mono text-gray-500">{currency.format(p.totalCost)}</td>
                                            <td className="p-4 text-right">
                                                <div className="flex flex-col items-end">
                                                    <span className={`text-xs font-mono font-bold ${p.gainLoss >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                                        {p.gainLoss >= 0 ? '+' : ''}{currency.format(p.gainLoss)}
                                                    </span>
                                                    <span className={`text-[9px] font-mono ${roi >= 0 ? 'text-emerald-400/60' : 'text-rose-400/60'}`}>
                                                        {roi >= 0 ? '+' : ''}{roi.toFixed(1)}%
                                                    </span>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                </section>

                {/* ΓòÉΓòÉΓòÉ CROSS-ACCOUNT ORDER BOOK ΓòÉΓòÉΓòÉ */}
                {allPendingOrders.length > 0 && (
                    <section className="glass-card p-6 space-y-4 animate-fade-in-up delay-200">
                        <div className="flex items-center justify-between">
                            <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">All Pending Orders</h3>
                            <span className="text-[9px] text-gray-600 font-mono">{allPendingOrders.length} orders ΓÇó {currency.format(totalStagedValue)} staged</span>
                        </div>
                        <div className="space-y-2">
                            {allPendingOrders.map(order => (
                                <div key={order.id} className="flex items-center justify-between p-3 rounded-xl bg-white/[0.02] border border-white/5">
                                    <div className="flex items-center gap-3">
                                        <span className={`text-[8px] font-black px-1.5 py-0.5 rounded border ${order.account === 'sui' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' : 'bg-purple-500/10 text-purple-400 border-purple-500/20'}`}>
                                            {order.account === 'sui' ? 'SUI' : 'ALTS'}
                                        </span>
                                        <span className={`text-[9px] font-black uppercase px-1.5 py-0.5 rounded border ${order.type === 'buy' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border-rose-500/20'}`}>
                                            {order.type}
                                        </span>
                                        <div className="flex items-center gap-1.5">
                                            {LOGO_MAPPING[order.symbol] && <img src={LOGO_MAPPING[order.symbol]} alt="" className="w-4 h-4" />}
                                            <span className="text-xs font-bold text-white">{order.symbol}</span>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4 text-[10px] font-mono">
                                        <span className="text-gray-400">{order.units} @ {currency.format(order.price)}</span>
                                        <span className="text-white font-bold">{currency.format(order.units * order.price)}</span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </section>
                )}

                <div className="h-10"></div>
              </div>
            </div>
        </>
    );
}

import { useEffect, useRef } from 'react';
import { usePortfolio } from '@/contexts/labs/smartfolio/PortfolioContext';

// TradingView Widget Configuration
declare global {
    interface Window {
        TradingView: any;
    }
}

const REGIMES = [
    { id: 'accumulation', label: 'Accumulation', icon: '≡ƒº║', color: 'text-emerald-400', desc: 'Buy dips. Range-bound with upward bias.' },
    { id: 'bull', label: 'Risk On / Bull', icon: '≡ƒÜÇ', color: 'text-blue-400', desc: 'Trend is your friend. Full allocation.' },
    { id: 'distribution', label: 'Profit Taking', icon: '≡ƒÆ░', color: 'text-amber-400', desc: 'Sell strength. Wall St distribution likely.' },
    { id: 'bear', label: 'Risk Off / Bear', icon: '≡ƒ¢í∩╕Å', color: 'text-rose-400', desc: 'Cash is king. Protect capital.' },
    { id: 'choppiness', label: 'Chop / Noise', icon: '≡ƒîè', color: 'text-gray-400', desc: 'Sideways volatility. Avoid over-trading.' },
] as const;

export function SmartFolioMarket() {
    const { marketCondition, setMarketCondition, fearGreed } = usePortfolio();
    const container = useRef<HTMLDivElement>(null);
    const widgetRef = useRef<any>(null);

    // Initialize TradingView Widget
    useEffect(() => {
        const script = document.createElement("script");
        script.src = "https://s3.tradingview.com/tv.js";
        script.async = true;
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        script.onload = () => {
            if (window.TradingView && container.current) {
                // Destroy previous widget if it exists
                if (widgetRef.current) {
                    widgetRef.current.remove();
                }

                // Create and store new widget
                widgetRef.current = new window.TradingView.widget({
                    "width": "100%",
                    "height": "100%",
                    "symbol": "COINBASE:BTCUSD",
                    "interval": "D",
                    "timezone": "Etc/UTC",
                    "theme": "dark",
                    "style": "1",
                    "locale": "en",
                    "toolbar_bg": "#f1f3f6",
                    "enable_publishing": false,
                    "allow_symbol_change": true,
                    "container_id": "tradingview_widget"
                });
            }
        };
        document.head.appendChild(script);
        return () => {
            if (script.parentNode) script.parentNode.removeChild(script);
            if (widgetRef.current) {
                try {
                    widgetRef.current.remove();
                    widgetRef.current = null;
                } catch (err) {
                    console.warn('[TradingView] Cleanup failed:', err);
                }
            }
        };
    }, []);

    return (
        <div className="h-full flex flex-col p-6 space-y-6 overflow-hidden">
            {/* Header / Regime Selector */}
            <div className="flex flex-col lg:flex-row gap-6 shrink-0">
                <div className="glass-card p-6 flex-1 space-y-4">
                    <div className="flex justify-between items-start">
                        <div>
                            <h2 className="text-xl font-black text-white uppercase tracking-tighter">Market Regime</h2>
                            <p className="text-xs text-gray-400 font-mono mt-1">Manual Override: Define the current macro environment.</p>
                        </div>
                        <div className="px-3 py-1 rounded bg-white/5 border border-white/10 text-[10px] font-mono text-gray-500 uppercase">
                            Global Signal
                        </div>
                    </div>

                    <div className="grid grid-cols-2 lg:grid-cols-5 gap-3">
                        {REGIMES.map((r) => (
                            <button
                                key={r.id}
                                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                onClick={() => setMarketCondition(r.id as any)}
                                className={`flex flex-col items-center p-3 rounded-xl border transition-all ${marketCondition === r.id
                                    ? `bg-white/10 border-white/20 shadow-[0_0_15px_rgba(255,255,255,0.1)] scale-[1.02]`
                                    : 'bg-white/[0.02] border-white/5 hover:bg-white/5 opacity-60 hover:opacity-100'
                                    }`}
                            >
                                <span className="text-2xl mb-2">{r.icon}</span>
                                <span className={`text-[10px] font-black uppercase tracking-wider ${r.color}`}>{r.label}</span>
                            </button>
                        ))}
                    </div>

                    {/* Active Regime Description */}
                    <div className="p-3 rounded-lg bg-black/40 border border-white/5 flex items-center justify-between">
                        <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">Current Doctrine</span>
                        <span className="text-xs text-white font-mono">
                            {REGIMES.find(r => r.id === marketCondition)?.desc}
                        </span>
                    </div>
                </div>

                {/* Fear & Greed Index */}
                <div className="lg:w-1/3">
                    <div className="glass-card p-6 h-full flex flex-col justify-between">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-sm font-black text-gray-400 uppercase tracking-widest">Fear & Greed</h2>
                            <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                        </div>

                        {fearGreed ? (
                            <div className="flex flex-col items-center gap-4">
                                <div className="relative flex items-center justify-center">
                                    {/* Semi-circle Gauge logic could go here, but a clean text/desc is premium too */}
                                    <div className={`text-6xl font-black tracking-tighter ${fearGreed.value > 75 ? 'text-emerald-400' : fearGreed.value < 25 ? 'text-rose-400' : 'text-blue-400'
                                        }`}>
                                        {fearGreed.value}
                                    </div>
                                    <span className="absolute -bottom-2 text-[10px] text-gray-500 font-mono uppercase tracking-widest">/ 100</span>
                                </div>
                                <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border ${fearGreed.value > 75 ? 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30' :
                                    fearGreed.value < 25 ? 'bg-rose-500/20 text-rose-400 border-rose-500/30' :
                                        'bg-blue-500/20 text-blue-400 border-blue-500/30'
                                    }`}>
                                    {fearGreed.classification}
                                </div>
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center gap-3">
                                <div className="w-8 h-8 rounded-full border-2 border-t-blue-500 border-white/5 animate-spin"></div>
                                <span className="text-[10px] text-gray-600 font-mono uppercase animate-pulse">Scanning Sentiment...</span>
                            </div>
                        )}

                        <div className="mt-6 pt-4 border-t border-white/5 text-[9px] text-gray-500 text-center uppercase tracking-widest font-bold">
                            Live Alternative.me Feed
                        </div>
                    </div>
                </div>
            </div>

            {/* Chart Area */}
            <div className="flex-1 glass-card p-4 overflow-hidden relative border border-white/10 rounded-2xl min-h-[500px]">
                <div id="tradingview_widget" ref={container} className="w-full h-full" />
            </div>
        </div>
    );
}

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { usePortfolio } from '@/contexts/labs/smartfolio/PortfolioContext';
import { ACCOUNTS, type AccountId, LOGO_MAPPING } from '@/lib/smartfolio/store/portfolio';
import { TRADE_FEE_PERCENT, STRATEGIES } from '@/lib/smartfolio/store/strategy';
import { hasGeminiKey, analyzePortfolio, type PortfolioSnapshot } from '@/lib/smartfolio/geminiService';

const currency = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' });

export function SmartFolioReport() {
    const { assets, pendingOrders, activeAccount, activeStrategy, recycledToSui, mounted, marketCondition } = usePortfolio();
    const [mounted2, setMounted2] = useState(false);
    const [aiBrief, setAiBrief] = useState<string | null>(null);
    const [aiBriefLoading, setAiBriefLoading] = useState(false);
    const [isGemini, setIsGemini] = useState(false);
    React.useEffect(() => setMounted2(true), []);

    const totalValue = assets.reduce((s, a) => s + a.currentValue, 0);
    const coins = assets.filter(a => a.symbol !== 'USD');
    const cashAsset = assets.find(a => a.symbol === 'USD');
    const cashPercent = cashAsset ? (cashAsset.currentValue / totalValue) * 100 : 0;

    // ΓöÇΓöÇΓöÇ Strategy compliance ΓöÇΓöÇΓöÇ
    const compliance = useMemo(() => {
        const targets = activeStrategy.targets;
        const checks: { label: string; target: string; actual: string; status: 'pass' | 'warn' | 'fail' }[] = [];

        // Cash check
        const cashMin = targets.cash.min || 10;
        const cashIdeal = targets.cash.ideal || 25;
        checks.push({
            label: 'Cash Reserve',
            target: `${cashMin}ΓÇô${cashIdeal}%`,
            actual: `${cashPercent.toFixed(1)}%`,
            status: cashPercent >= cashMin ? (cashPercent >= cashIdeal * 0.8 ? 'pass' : 'warn') : 'fail',
        });

        if (activeAccount === 'sui') {
            // SUI anchor check
            const suiAlloc = assets.find(a => a.symbol === 'SUI')?.allocation || 0;
            const suiTarget = targets.sui;
            checks.push({
                label: 'SUI Anchor Weight',
                target: `${suiTarget.min}ΓÇô${suiTarget.max}%`,
                actual: `${suiAlloc.toFixed(1)}%`,
                status: suiAlloc >= (suiTarget.min || 0) ? (suiAlloc <= (suiTarget.max || 100) ? 'pass' : 'warn') : 'fail',
            });

            // Alts check
            const altAlloc = coins.filter(a => a.symbol !== 'SUI').reduce((s, a) => s + a.allocation, 0);
            checks.push({
                label: 'Alt Exposure',
                target: `${targets.alts.min}ΓÇô${targets.alts.max}%`,
                actual: `${altAlloc.toFixed(1)}%`,
                status: altAlloc <= (targets.alts.max || 100) ? 'pass' : 'warn',
            });
        } else {
            // Concentration check
            const maxAlloc = Math.max(...coins.map(a => a.allocation));
            const maxSymbol = coins.find(a => a.allocation === maxAlloc)?.symbol || '?';
            checks.push({
                label: `Max Concentration (${maxSymbol})`,
                target: `Γëñ${activeStrategy.thresholds.maxConcentration}%`,
                actual: `${maxAlloc.toFixed(1)}%`,
                status: maxAlloc <= activeStrategy.thresholds.maxConcentration ? 'pass' : 'warn',
            });

            // Position count
            checks.push({
                label: 'Position Count',
                target: '4ΓÇô8 alts',
                actual: `${coins.length} positions`,
                status: coins.length >= 4 && coins.length <= 8 ? 'pass' : 'warn',
            });
        }

        return checks;
    }, [assets, activeAccount, activeStrategy, cashPercent, coins]);

    const score = compliance.filter(c => c.status === 'pass').length / compliance.length * 100;

    // ΓöÇΓöÇΓöÇ Best / Worst performers ΓöÇΓöÇΓöÇ
    const sorted = [...coins].sort((a, b) => (b.gainLoss || 0) - (a.gainLoss || 0));
    const bestPerformers = sorted.filter(a => (a.gainLoss || 0) > 0).slice(0, 3);
    const worstPerformers = sorted.filter(a => (a.gainLoss || 0) < 0).slice(-3).reverse();

    // ΓöÇΓöÇΓöÇ Fee drag estimate ΓöÇΓöÇΓöÇ
    const totalFeeDrag = useMemo(() => {
        // Estimate fees from orders + past fills
        const orderFeeDrag = pendingOrders.reduce((s, o) => s + o.units * o.price * TRADE_FEE_PERCENT / 100, 0);
        return orderFeeDrag;
    }, [pendingOrders]);

    // ΓöÇΓöÇΓöÇ Cross-account summary ΓöÇΓöÇΓöÇ
    const otherAccountId: AccountId = activeAccount === 'sui' ? 'alts' : 'sui';
    const otherAssets = ACCOUNTS[otherAccountId].assets;
    const otherTotal = otherAssets.reduce((s, a) => s + a.currentValue, 0);
    const combinedTotal = totalValue + otherTotal;
    const otherCoins = otherAssets.filter(a => a.symbol !== 'USD');

    // ΓöÇΓöÇΓöÇ Trade recommendations ΓöÇΓöÇΓöÇ
    const recommendations = useMemo(() => {
        const recs: { icon: string; text: string; priority: 'high' | 'medium' | 'low' }[] = [];
        const cashTargets = activeStrategy.targets.cash;
        const cashMin = cashTargets.min || 10;
        const cashIdeal = cashTargets.ideal || 25;

        // Dynamic Cash Checks
        if (cashPercent < cashMin) {
            recs.push({ icon: '≡ƒÜ¿', text: `Cash critically low at ${cashPercent.toFixed(1)}% (Min: ${cashMin}%). Sell positions to rebuild dry powder.`, priority: 'high' });
        } else if (cashPercent < cashIdeal * 0.9) {
            recs.push({ icon: 'ΓÜá∩╕Å', text: `Cash at ${cashPercent.toFixed(1)}% ΓÇö below ideal ${cashIdeal}%. Monitor for opportunities to take profit.`, priority: 'medium' });
        }

        coins.forEach(a => {
            const roi = a.totalCost ? ((a.gainLoss || 0) / a.totalCost) * 100 : 0;
            const deviation = a.allocation - a.targetAllocation;

            // Pending Order Awareness
            const pendingBuys = pendingOrders.filter(o => o.symbol === a.symbol && o.type === 'buy');
            const pendingSells = pendingOrders.filter(o => o.symbol === a.symbol && o.type === 'sell');
            const hasPendingSell = pendingSells.length > 0;
            const hasPendingBuy = pendingBuys.length > 0;

            // Profit taking
            if (roi > 50) {
                if (hasPendingSell) {
                    recs.push({ icon: 'Γ£à', text: `${a.symbol} is +${roi.toFixed(0)}% ROI. Profit-taking order already staged.`, priority: 'low' });
                } else {
                    recs.push({ icon: '≡ƒÆ░', text: `${a.symbol} is +${roi.toFixed(0)}% ROI. Consider taking 25-50% profit.`, priority: 'medium' });
                }
            } else if (roi < -30) {
                recs.push({ icon: '≡ƒôë', text: `${a.symbol} is ${roi.toFixed(0)}% ROI. Evaluate thesis ΓÇö hold or cut losses.`, priority: 'medium' });
            }

            // Rebalancing
            if (deviation > 5) { // Significantly Overweight
                if (hasPendingSell) {
                    recs.push({ icon: 'Γ£à', text: `${a.symbol} overweight (${a.allocation.toFixed(1)}%). Trim order staged.`, priority: 'low' });
                } else {
                    recs.push({ icon: 'ΓÜû∩╕Å', text: `${a.symbol} at ${a.allocation.toFixed(1)}% ΓÇö overweight (target: ${a.targetAllocation.toFixed(1)}%). Trim suggested.`, priority: 'high' });
                }
            } else if (deviation < -5) { // Significantly Underweight
                if (hasPendingBuy) {
                    recs.push({ icon: 'Γ£à', text: `${a.symbol} underweight. Buy order staged.`, priority: 'low' });
                } else {
                    // Only suggest buying if cash allows
                    if (cashPercent > cashMin) {
                        recs.push({ icon: '≡ƒ¢Æ', text: `${a.symbol} underweight (${a.allocation.toFixed(1)}%). Consider adding on dips.`, priority: 'medium' });
                    }
                }
            }
        });

        if (recs.length === 0) {
            recs.push({ icon: 'Γ£¿', text: 'Portfolio is balanced and strategy compliant. No actions needed.', priority: 'low' });
        } else if (pendingOrders.length === 0 && recs.some(r => r.priority === 'high')) {
            recs.push({ icon: '≡ƒôï', text: 'High priority items detected. Use Order Builder to stage actions.', priority: 'high' });
        }

        return recs;
    }, [assets, cashPercent, coins, pendingOrders, activeStrategy]);

    // ΓöÇΓöÇΓöÇ Gemini Weekly Brief ΓöÇΓöÇΓöÇ
    const buildReportSnapshot = useCallback((): PortfolioSnapshot => {
        return {
            accountName: activeAccount === 'sui' ? 'SUI Account' : 'Alts Account',
            strategyName: activeStrategy.name,
            targetMask: activeStrategy.targetMask,
            marketRegime: marketCondition || 'unknown',
            totalValue,
            cashPercent,
            positions: coins.map(a => ({
                symbol: a.symbol,
                units: a.units,
                avgCost: a.avgCost,
                currentPrice: a.currentPrice,
                currentValue: a.currentValue,
                allocation: a.allocation,
                targetAllocation: a.targetAllocation,
                gainLoss: a.gainLoss,
            })),
            pendingOrders: pendingOrders.map(o => ({
                type: o.type,
                symbol: o.symbol,
                units: o.units,
                price: o.price,
                note: o.note,
            })),
            strategyRules: activeStrategy.rules,
        };
    }, [activeAccount, activeStrategy, coins, pendingOrders, marketCondition, totalValue, cashPercent]);

    const generateBrief = useCallback(async () => {
        if (!hasGeminiKey()) return;
        setAiBriefLoading(true);
        try {
            const snapshot = buildReportSnapshot();
            const persona = activeAccount === 'sui' ? 'anchor' as const : 'tactician' as const;
            const complianceSummary = compliance.map(c => `${c.label}: ${c.actual} (target ${c.target}) ΓÇö ${c.status}`).join('; ');
            const response = await analyzePortfolio(snapshot, persona,
                `Write a concise weekly portfolio brief (150-200 words). Structure with:\n` +
                `1. **Status**: One-line overall health assessment\n` +
                `2. **Performance**: Key PnL highlights, best/worst performers\n` +
                `3. **Compliance**: ${complianceSummary}\n` +
                `4. **Action Items**: Top 2-3 specific trades or adjustments with exact numbers\n` +
                `5. **Outlook**: 1-2 sentence forward view based on current regime\n` +
                `Use bold for key numbers. Be specific with prices, units, and percentages.`
            );
            setAiBrief(response.text);
        } catch {
            setAiBrief('ΓÜá∩╕Å Failed to generate AI brief. Check Gemini API key in Settings.');
        }
        setAiBriefLoading(false);
    }, [buildReportSnapshot, activeAccount, compliance]);

    useEffect(() => {
        const geminiAvailable = hasGeminiKey();
        setIsGemini(geminiAvailable);
        if (geminiAvailable && mounted && mounted2) {
            generateBrief();
        }
    }, [mounted, mounted2, activeAccount]);

    if (!mounted || !mounted2) return null;

    return (
        <>
            <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-xl flex items-center justify-between px-6 z-30 sticky top-0">
                <div className="flex items-center gap-3">
                    <span className="text-lg">≡ƒôï</span>
                    <h1 className="text-sm font-black text-white uppercase tracking-widest">Portfolio Report</h1>
                </div>
                <div className="flex items-center gap-4">
                    <span className="text-[9px] text-gray-500 font-mono bg-white/5 px-2 py-0.5 rounded border border-white/10">
                        Generated {new Date().toLocaleDateString()}
                    </span>
                </div>
            </header>

            <div className="flex-1 overflow-y-auto p-6 pb-20 custom-scrollbar relative z-10">
              <div className="max-w-[2000px] mx-auto space-y-6">
                {/* ΓòÉΓòÉΓòÉ STRATEGY SCORECARD ΓòÉΓòÉΓòÉ */}
                <div className="glass-card p-6 space-y-5">
                    <div className="flex items-center justify-between">
                        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">Strategy Compliance</h3>
                        <div className="flex items-center gap-3">
                            <span className="text-[10px] text-gray-500 font-mono">{activeStrategy.name}</span>
                            <div className={`px-3 py-1 rounded-lg text-xs font-black ${score >= 80 ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' :
                                score >= 50 ? 'bg-amber-500/20 text-amber-400 border border-amber-500/30' :
                                    'bg-rose-500/20 text-rose-400 border border-rose-500/30'
                                }`}>
                                {score.toFixed(0)}% Score
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                        {compliance.map((check, i) => (
                            <div key={i} className={`p-4 rounded-xl border ${check.status === 'pass' ? 'bg-emerald-500/5 border-emerald-500/20' :
                                check.status === 'warn' ? 'bg-amber-500/5 border-amber-500/20' :
                                    'bg-rose-500/5 border-rose-500/20'
                                }`}>
                                <div className="flex items-center gap-2 mb-2">
                                    <span className="text-sm">{check.status === 'pass' ? 'Γ£à' : check.status === 'warn' ? 'ΓÜá∩╕Å' : '≡ƒÜ¿'}</span>
                                    <span className="text-[10px] font-bold text-gray-400 uppercase">{check.label}</span>
                                </div>
                                <div className="text-base font-black font-mono text-white">{check.actual}</div>
                                <div className="text-[9px] text-gray-600 font-mono mt-1">Target: {check.target}</div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* ΓòÉΓòÉΓòÉ BEST PERFORMERS ΓòÉΓòÉΓòÉ */}
                    <div className="glass-card p-6 space-y-4">
                        <h3 className="text-xs font-black text-emerald-400 uppercase tracking-[0.2em]">≡ƒÅå Best Performers</h3>
                        {bestPerformers.length > 0 ? bestPerformers.map((a, i) => (
                            <div key={a.symbol} className="flex items-center justify-between p-3 rounded-xl bg-emerald-500/5 border border-emerald-500/20">
                                <div className="flex items-center gap-3">
                                    <span className="text-lg">{i === 0 ? '≡ƒÑç' : i === 1 ? '≡ƒÑê' : '≡ƒÑë'}</span>
                                    <div className="flex items-center gap-2">
                                        {LOGO_MAPPING[a.symbol] && <img src={LOGO_MAPPING[a.symbol]} alt="" className="w-5 h-5" />}
                                        <span className="text-sm font-black text-white">{a.symbol}</span>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <span className="text-sm font-black font-mono text-emerald-400">+{currency.format(a.gainLoss || 0)}</span>
                                    <div className="text-[9px] text-gray-500 font-mono">{a.totalCost ? `+${(((a.gainLoss || 0) / a.totalCost) * 100).toFixed(1)}% ROI` : ''}</div>
                                </div>
                            </div>
                        )) : (
                            <p className="text-xs text-gray-600 font-mono text-center py-4">No green positions</p>
                        )}
                    </div>

                    {/* ΓòÉΓòÉΓòÉ WORST PERFORMERS ΓòÉΓòÉΓòÉ */}
                    <div className="glass-card p-6 space-y-4">
                        <h3 className="text-xs font-black text-rose-400 uppercase tracking-[0.2em]">≡ƒôë Needs Attention</h3>
                        {worstPerformers.length > 0 ? worstPerformers.map(a => (
                            <div key={a.symbol} className="flex items-center justify-between p-3 rounded-xl bg-rose-500/5 border border-rose-500/20">
                                <div className="flex items-center gap-2">
                                    {LOGO_MAPPING[a.symbol] && <img src={LOGO_MAPPING[a.symbol]} alt="" className="w-5 h-5" />}
                                    <span className="text-sm font-black text-white">{a.symbol}</span>
                                </div>
                                <div className="text-right">
                                    <span className="text-sm font-black font-mono text-rose-400">{currency.format(a.gainLoss || 0)}</span>
                                    <div className="text-[9px] text-gray-500 font-mono">{a.totalCost ? `${(((a.gainLoss || 0) / a.totalCost) * 100).toFixed(1)}% ROI` : ''}</div>
                                </div>
                            </div>
                        )) : (
                            <p className="text-xs text-gray-600 font-mono text-center py-4">All positions are green ≡ƒÄë</p>
                        )}
                    </div>
                </div>

                {/* ΓòÉΓòÉΓòÉ TRADE RECOMMENDATIONS ΓòÉΓòÉΓòÉ */}
                <div className="glass-card p-6 space-y-4">
                    <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">AI Recommendations</h3>
                    {recommendations.length > 0 ? (
                        <div className="space-y-3">
                            {recommendations.sort((a, b) => {
                                const p = { high: 0, medium: 1, low: 2 };
                                return p[a.priority] - p[b.priority];
                            }).map((rec, i) => (
                                <div key={i} className={`p-4 rounded-xl border flex items-start gap-3 ${rec.priority === 'high' ? 'bg-rose-500/5 border-rose-500/20' :
                                    rec.priority === 'medium' ? 'bg-amber-500/5 border-amber-500/20' :
                                        'bg-white/[0.02] border-white/5'
                                    }`}>
                                    <span className="text-lg">{rec.icon}</span>
                                    <div className="flex-1">
                                        <p className="text-xs text-gray-300 leading-relaxed">{rec.text}</p>
                                    </div>
                                    <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded border ${rec.priority === 'high' ? 'text-rose-400 border-rose-500/30' :
                                        rec.priority === 'medium' ? 'text-amber-400 border-amber-500/30' :
                                            'text-gray-500 border-white/10'
                                        }`}>{rec.priority}</span>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <p className="text-xs text-gray-600 font-mono text-center py-4">Portfolio looks well-balanced. No action needed.</p>
                    )}
                </div>

                {/* ΓòÉΓòÉΓòÉ AI WEEKLY BRIEF ΓòÉΓòÉΓòÉ */}
                <div className="glass-card p-6 space-y-4">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">≡ƒºá AI Weekly Brief</h3>
                            {isGemini && (
                                <span className="text-[8px] font-bold text-emerald-400 bg-emerald-500/10 px-1.5 py-0.5 rounded border border-emerald-500/20">Gemini 2.5 Pro</span>
                            )}
                        </div>
                        {isGemini && (
                            <button
                                onClick={generateBrief}
                                disabled={aiBriefLoading}
                                className="text-[9px] font-bold text-blue-400 hover:text-blue-300 bg-blue-500/10 hover:bg-blue-500/20 px-3 py-1 rounded-lg border border-blue-500/20 transition-all disabled:opacity-50"
                            >
                                {aiBriefLoading ? 'Generating...' : 'Γå╗ Regenerate'}
                            </button>
                        )}
                    </div>

                    {aiBriefLoading ? (
                        <div className="flex items-center gap-3 py-8 justify-center">
                            <div className="flex gap-1">
                                <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"></span>
                            </div>
                            <span className="text-xs text-gray-500 font-mono">Gemini analyzing portfolio...</span>
                        </div>
                    ) : aiBrief ? (
                        <div className="p-5 rounded-xl bg-gradient-to-br from-blue-900/10 to-purple-900/10 border border-white/5">
                            <div className="text-xs text-gray-300 leading-relaxed whitespace-pre-wrap font-medium">
                                {aiBrief}
                            </div>
                            <div className="mt-4 pt-3 border-t border-white/5 flex justify-between items-center">
                                <span className="text-[8px] text-gray-600 font-mono">Generated {new Date().toLocaleTimeString()}</span>
                                <span className="text-[8px] text-gray-600 font-mono">Strategy: {activeStrategy.name}</span>
                            </div>
                        </div>
                    ) : (
                        <div className="text-center py-8">
                            <p className="text-xs text-gray-600 font-mono">Add your Gemini API key in Settings to enable AI-powered portfolio briefs.</p>
                        </div>
                    )}
                </div>

                {/* ΓòÉΓòÉΓòÉ CROSS-ACCOUNT SUMMARY ΓòÉΓòÉΓòÉ */}
                <div className="glass-card p-6 space-y-5">
                    <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">Cross-Account Summary</h3>

                    <div className="grid grid-cols-2 gap-6">
                        {/* Active account */}
                        <div className="p-5 rounded-xl bg-blue-500/5 border border-blue-500/20 space-y-3">
                            <div className="flex items-center gap-2">
                                <span className="text-sm">{activeAccount === 'sui' ? '≡ƒææ' : '≡ƒöä'}</span>
                                <span className="text-xs font-black text-white uppercase">{ACCOUNTS[activeAccount].accountName}</span>
                                <span className="text-[8px] bg-blue-500/20 text-blue-400 px-1.5 py-0.5 rounded border border-blue-500/30">ACTIVE</span>
                            </div>
                            <div className="text-xl font-black font-mono text-white">{currency.format(totalValue)}</div>
                            <div className="space-y-1 text-[9px] text-gray-500 font-mono">
                                <div>Strategy: {activeStrategy.name}</div>
                                <div>Positions: {coins.length} coins + cash</div>
                                <div>Pending orders: {pendingOrders.length}</div>
                                <div>Cash: {cashPercent.toFixed(1)}%</div>
                                {activeAccount === 'sui' && <div>Recycled to SUI: {currency.format(recycledToSui)}</div>}
                            </div>
                        </div>

                        {/* Other account */}
                        <div className="p-5 rounded-xl bg-white/[0.02] border border-white/5 space-y-3">
                            <div className="flex items-center gap-2">
                                <span className="text-sm">{otherAccountId === 'sui' ? '≡ƒææ' : '≡ƒöä'}</span>
                                <span className="text-xs font-black text-gray-400 uppercase">{ACCOUNTS[otherAccountId].accountName}</span>
                            </div>
                            <div className="text-xl font-black font-mono text-gray-400">{currency.format(otherTotal)}</div>
                            <div className="space-y-1 text-[9px] text-gray-600 font-mono">
                                <div>Strategy: {STRATEGIES[otherAccountId].name}</div>
                                <div>Positions: {otherCoins.length} coins + cash</div>
                                <div>Pending orders: {ACCOUNTS[otherAccountId].pendingOrders.length}</div>
                                <div>Cash: {((otherAssets.find(a => a.symbol === 'USD')?.currentValue || 0) / otherTotal * 100).toFixed(1)}%</div>
                            </div>
                        </div>
                    </div>

                    <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5 flex items-center justify-between">
                        <div className="flex flex-col">
                            <span className="text-[9px] text-gray-600 uppercase tracking-widest">Combined AUM</span>
                            <span className="text-xl font-black font-mono text-blue-400">{currency.format(combinedTotal)}</span>
                        </div>
                        <div className="flex flex-col items-end">
                            <span className="text-[9px] text-gray-600 uppercase tracking-widest">Total Fee Drag (Pending)</span>
                            <span className="text-sm font-black font-mono text-amber-400">{currency.format(totalFeeDrag)}</span>
                        </div>
                    </div>
                </div>
              </div>
            </div>
        </>
    );
}

"use client";
import { useState, useMemo, useEffect } from 'react';
import { usePortfolio } from '@/contexts/labs/smartfolio/PortfolioContext';
import { ACCOUNTS, type AccountId, LOGO_MAPPING } from '@/lib/smartfolio/store/portfolio';
import { TRADE_FEE_PERCENT } from '@/lib/smartfolio/store/strategy';

const currency = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' });

export function SmartFolioRisk() {
    const { assets, activeAccount, activeStrategy, pendingOrders, mounted } = usePortfolio();
    const [stressPercent, setStressPercent] = useState(-30);
    const [stressSymbol, setStressSymbol] = useState('ALL');
    const [customPrices, setCustomPrices] = useState<Record<string, number>>({});
    const [simulateFills, setSimulateFills] = useState(false);
    const [mounted2, setMounted2] = useState(false);

    useEffect(() => setMounted2(true), []);
    // Reset simulation on account switch
    useEffect(() => { setCustomPrices({}); setSimulateFills(false); }, [activeAccount]);

    const copyToClipboard = (txt: string | number) => {
        if (!txt) return;
        navigator.clipboard.writeText(String(txt));
    };

    // ΓöÇΓöÇΓöÇ Simulation Engine ΓöÇΓöÇΓöÇ
    const simulatedData = useMemo(() => {
        // 1. Apply Price Overrides
        let currentAssets = assets.map(a => {
            const price = customPrices[a.symbol] ?? a.currentPrice;
            const val = price * a.units;
            return { ...a, currentPrice: price, currentValue: val, isSimulated: customPrices[a.symbol] !== undefined };
        });

        // 2. Apply Pending Fills (if enabled)
        if (simulateFills) {
            let cash = currentAssets.find(a => a.symbol === 'USD')?.currentValue || 0;
            const assetMap = new Map(currentAssets.map(a => [a.symbol, a]));

            pendingOrders.forEach(order => {
                const asset = assetMap.get(order.symbol);
                const gross = order.units * order.price; // execute at limit price
                const fee = gross * (TRADE_FEE_PERCENT / 100);

                if (order.type === 'buy') {
                    // Decrease Cash
                    cash -= (gross + fee);
                    // Increase Asset
                    if (asset) {
                        const newUnits = asset.units + order.units;
                        const newVal = newUnits * asset.currentPrice; // value at *current/simulated* price
                        assetMap.set(order.symbol, { ...asset, units: newUnits, currentValue: newVal });
                    }
                } else {
                    // Sell
                    // Increase Cash
                    cash += (gross - fee);
                    // Decrease Asset
                    if (asset) {
                        const newUnits = Math.max(0, asset.units - order.units);
                        const newVal = newUnits * asset.currentPrice;
                        assetMap.set(order.symbol, { ...asset, units: newUnits, currentValue: newVal });
                    }
                }
            });

            // Update assets list with modified values
            currentAssets = Array.from(assetMap.values());
            // Update Cash asset
            const cashIndex = currentAssets.findIndex(a => a.symbol === 'USD');
            if (cashIndex !== -1) currentAssets[cashIndex] = { ...currentAssets[cashIndex], currentValue: cash, units: cash };
        }

        const total = currentAssets.reduce((s, a) => s + a.currentValue, 0);
        return {
            totalValue: total,
            assets: currentAssets.map(a => ({ ...a, allocation: total > 0 ? (a.currentValue / total) * 100 : 0 }))
        };
    }, [assets, customPrices, simulateFills, pendingOrders, activeAccount]);

    const { assets: simulatedAssets, totalValue } = simulatedData;
    const coins = simulatedAssets.filter(a => a.symbol !== 'USD');

    // ΓöÇΓöÇΓöÇ Rebalance Logic (Smart) ΓöÇΓöÇΓöÇ
    const rebalanceSuggestions = useMemo(() => {
        return coins.map(a => {
            // Note: Strategy targets are complex, simplified here to use asset-level targetAllocation which comes from portfolio.ts
            // We use the asset's targetAllocation as the source of truth for the dashboard to match the bar charts.

            const targetValue = totalValue * (a.targetAllocation / 100);
            const diff = targetValue - a.currentValue; // Positive = Buy, Negative = Sell
            const absDiff = Math.abs(diff);
            const neededChange = diff; // $ amount

            // Pending Order Awareness
            const pendingBuys = pendingOrders.filter(o => o.symbol === a.symbol && o.type === 'buy');
            const pendingSells = pendingOrders.filter(o => o.symbol === a.symbol && o.type === 'sell');
            const pendingBuyVal = pendingBuys.reduce((s, o) => s + (o.units * o.price), 0);
            const pendingSellVal = pendingSells.reduce((s, o) => s + (o.units * o.price), 0);

            let action = 'HOLD';
            let status = ' actionable';
            let remainingVal = absDiff;
            let coverMsg = '';

            // Thresholds ($10 noise filter due to simulation)
            if (diff < -10) {
                action = 'TRIM';
                if (pendingSellVal >= absDiff * 0.9) {
                    status = 'COVERED';
                    const coveringOrder = pendingSells.sort((a, b) => b.price - a.price)[0]; // highest sell
                    coverMsg = `Covered by pending sell (${coveringOrder?.units.toFixed(0)} @ ${coveringOrder?.price})`;
                } else if (pendingSellVal > 0) {
                    status = 'PARTIAL';
                    remainingVal = absDiff - pendingSellVal;
                    coverMsg = `Partially covered ($${pendingSellVal.toFixed(0)} pending)`;
                }
            } else if (diff > 10) {
                action = 'ADD';
                if (pendingBuyVal >= absDiff * 0.9) {
                    status = 'COVERED';
                    const coveringOrder = pendingBuys.sort((a, b) => a.price - b.price)[0]; // lowest buy
                    coverMsg = `Covered by pending buy (${coveringOrder?.units.toFixed(0)} @ ${coveringOrder?.price})`;
                } else if (pendingBuyVal > 0) {
                    status = 'PARTIAL';
                    remainingVal = absDiff - pendingBuyVal;
                    coverMsg = `Partially covered ($${pendingBuyVal.toFixed(0)} pending)`;
                }
            }

            return {
                ...a, targetValue, diff, absDiff, neededChange, action, status, remainingVal, coverMsg,
                tradeUnitsApprox: Math.abs(remainingVal / a.currentPrice)
            };
        }).filter(a => a.action !== 'HOLD').sort((a, b) => b.absDiff - a.absDiff);
    }, [coins, totalValue, pendingOrders, activeStrategy]);


    // ΓöÇΓöÇΓöÇ Stress Test Logic ΓöÇΓöÇΓöÇ
    const stressResults = useMemo(() => {
        const pct = stressPercent / 100;
        return simulatedAssets.map(a => {
            if (a.symbol === 'USD') return { ...a, stressedValue: a.currentValue, delta: 0, stressedAlloc: 0 };
            const applies = stressSymbol === 'ALL' || stressSymbol === a.symbol;
            const stressedValue = applies ? a.currentValue * (1 + pct) : a.currentValue;
            const delta = stressedValue - a.currentValue;
            return { ...a, stressedValue, delta, stressedAlloc: 0 };
        });
    }, [simulatedAssets, stressPercent, stressSymbol]);

    const stressedTotal = stressResults.reduce((s, a) => s + a.stressedValue, 0);
    const stressedWithAlloc = stressResults.map(a => ({ ...a, stressedAlloc: (a.stressedValue / stressedTotal) * 100 }));
    const totalDelta = stressedTotal - totalValue;

    // ΓöÇΓöÇΓöÇ Concentration & Drawdown ΓöÇΓöÇΓöÇ
    const sortedByAlloc = [...coins].sort((a, b) => b.allocation - a.allocation);
    const herfindahl = coins.reduce((s, a) => s + Math.pow(a.allocation / 100, 2), 0);
    const effectivePositions = 1 / (herfindahl || 1);

    const drawdowns = coins.map(a => {
        const costBasis = a.avgCost || a.currentPrice;
        const drawdownPct = ((a.currentPrice - costBasis) / costBasis) * 100;
        return { ...a, drawdownPct, costBasis };
    }).sort((a, b) => a.drawdownPct - b.drawdownPct);

    // ΓöÇΓöÇΓöÇ Cross-account Risk ΓöÇΓöÇΓöÇ
    const otherAccountId: AccountId = activeAccount === 'sui' ? 'alts' : 'sui';
    const otherAssets = ACCOUNTS[otherAccountId]?.assets || [];
    const otherTotal = otherAssets.reduce((s, a) => s + a.currentValue, 0);
    const combinedTotal = totalValue + otherTotal;
    const activeSymbols = new Set(coins.map(a => a.symbol));
    const otherSymbols = new Set(otherAssets.filter(a => a.symbol !== 'USD').map(a => a.symbol));
    const overlapping = [...activeSymbols].filter(s => otherSymbols.has(s));

    if (!mounted || !mounted2) return null;

    return (
        <>
            <header className="h-14 border-b border-white/5 bg-black/40 backdrop-blur-xl flex items-center justify-between px-6 z-30 sticky top-0">
                <div className="flex items-center gap-3">
                    <span className="text-lg">≡ƒ¢í∩╕Å</span>
                    <h1 className="text-sm font-black text-white uppercase tracking-widest">Risk Guard</h1>
                    <span className="text-[9px] text-gray-500 font-mono bg-white/5 px-2 py-0.5 rounded border border-white/10">
                        HHI: {(herfindahl * 10000).toFixed(0)} ΓÇó Eff. Pos: {effectivePositions.toFixed(1)}
                    </span>
                </div>
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => setSimulateFills(!simulateFills)}
                        className={`text-[9px] font-black uppercase px-3 py-1 rounded-lg border transition-all flex items-center gap-2 ${simulateFills ? 'bg-purple-500 text-white border-purple-500 shadow-[0_0_10px_rgba(168,85,247,0.4)]' : 'bg-white/5 text-gray-500 border-white/10 hover:bg-white/10'}`}
                    >
                        {simulateFills ? 'Disable Fills' : 'Simulate Fills'}
                    </button>
                    {Object.keys(customPrices).length > 0 && (
                        <button onClick={() => setCustomPrices({})} className="text-[9px] font-black uppercase text-amber-400 bg-amber-500/10 px-3 py-1 rounded-lg border border-amber-500/20 hover:bg-amber-500/20 transition-all">
                            Reset Prices
                        </button>
                    )}
                </div>
            </header>

            <div className="flex-1 overflow-y-auto p-6 pb-20 custom-scrollbar">
              <div className="max-w-[2000px] mx-auto space-y-6">

                {/* ΓòÉΓòÉΓòÉ SCENARIO SIMULATOR ΓòÉΓòÉΓòÉ */}
                <div className="glass-card p-6 space-y-4 relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 opacity-10 text-6xl">≡ƒö«</div>
                    <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">Scenario Simulator</h3>
                    <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                        {coins.map(a => (
                            <div key={a.symbol} className="space-y-1">
                                <div className="flex justify-between items-center text-[9px]">
                                    <span className="text-gray-500 font-bold">{a.symbol} Price</span>
                                    {a.isSimulated && <span className="text-amber-400">Modified</span>}
                                </div>
                                <input
                                    type="number"
                                    value={a.currentPrice}
                                    onChange={(e) => setCustomPrices(prev => ({ ...prev, [a.symbol]: parseFloat(e.target.value) || 0 }))}
                                    step="0.0001"
                                    className={`w-full bg-white/5 border rounded-lg px-2 py-1.5 text-xs font-mono outline-none focus:border-blue-500/50 ${a.isSimulated ? 'border-amber-500/30 text-amber-300' : 'border-white/10 text-white'}`}
                                />
                            </div>
                        ))}
                    </div>
                </div>

                {/* ΓòÉΓòÉΓòÉ STRATEGY REBALANCER ΓòÉΓòÉΓòÉ */}
                {rebalanceSuggestions.length > 0 && (
                    <div className="glass-card p-6 space-y-4">
                        <div className="flex items-center justify-between">
                            <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] flex items-center gap-2">
                                Strategy Rebalancer
                                <span className="bg-blue-500/20 text-blue-400 px-1.5 rounded text-[9px]">Fee Aware</span>
                            </h3>
                            <span className="text-[9px] text-gray-600 font-mono">Based on target allocations</span>
                        </div>

                        <div className="space-y-3">
                            {rebalanceSuggestions.map(a => {
                                const isTrim = a.action === 'TRIM';
                                const isCovered = a.status === 'COVERED';

                                return (
                                    <div key={a.symbol} className={`p-4 rounded-xl border transition-all ${isTrim ? 'bg-rose-500/5 border-rose-500/20' : 'bg-emerald-500/5 border-emerald-500/20'} ${isCovered ? 'opacity-60 grayscale-[0.5]' : ''}`}>
                                        <div className="flex items-center justify-between">
                                            <div className="flex items-center gap-3">
                                                <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black ${isTrim ? 'bg-rose-500/20 text-rose-400 border border-rose-500/30' : 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30'}`}>
                                                    {isCovered ? 'Γ£ô' : (isTrim ? 'Γåô' : 'Γåæ')}
                                                </div>
                                                <div className="flex flex-col">
                                                    <div className="flex items-center gap-2">
                                                        <span className="text-sm font-black text-white">{a.symbol}</span>
                                                        <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded border ${isTrim ? 'bg-rose-500/10 text-rose-400 border-rose-500/20' : 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'}`}>
                                                            {a.action}
                                                        </span>
                                                        {a.status !== 'actionable' && (
                                                            <span className="text-[8px] font-bold text-gray-400 uppercase bg-white/5 px-1.5 rounded">
                                                                {a.status}
                                                            </span>
                                                        )}
                                                    </div>
                                                    <span className="text-[9px] text-gray-500 font-mono">
                                                        {a.allocation.toFixed(1)}% ΓåÆ {a.targetAllocation.toFixed(1)}% target
                                                    </span>
                                                </div>
                                            </div>
                                            <div className="text-right flex flex-col items-end">
                                                {!isCovered ? (
                                                    <>
                                                        <div className="flex items-center gap-2">
                                                            <button
                                                                onClick={() => copyToClipboard(a.tradeUnitsApprox.toFixed(a.currentPrice < 1 ? 0 : 4))}
                                                                className={`text-sm font-black font-mono hover:underline ${isTrim ? 'text-rose-400' : 'text-emerald-400'}`}
                                                                title="Click to copy units"
                                                            >
                                                                {isTrim ? 'Sell' : 'Buy'} {a.tradeUnitsApprox.toLocaleString(undefined, { maximumFractionDigits: 4 })}
                                                            </button>
                                                        </div>
                                                        <span className="text-[9px] text-gray-500 font-mono">
                                                            Γëê {currency.format(a.remainingVal)}
                                                            <span className="text-amber-500/70 ml-1">(fee: {currency.format(a.remainingVal * TRADE_FEE_PERCENT / 100)})</span>
                                                        </span>
                                                    </>
                                                ) : (
                                                    <span className="text-[10px] font-mono text-emerald-400">{a.coverMsg}</span>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                )}

                {/* ΓòÉΓòÉΓòÉ STRESS TEST ΓòÉΓòÉΓòÉ */}
                <div className="glass-card p-6 space-y-5">
                    <div className="flex items-center justify-between">
                        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] flex items-center gap-2">
                            Stress Test
                            <span className="w-1.5 h-1.5 rounded-full bg-rose-500 animate-pulse"></span>
                        </h3>
                        <div className="flex items-center gap-3">
                            <select value={stressSymbol} onChange={e => setStressSymbol(e.target.value)}
                                className="bg-white/5 border border-white/10 rounded-lg px-3 py-1.5 text-[10px] text-white font-mono outline-none"
                            >
                                <option value="ALL" className="bg-black">All Coins</option>
                                {coins.map(c => <option key={c.symbol} value={c.symbol} className="bg-black">{c.symbol}</option>)}
                            </select>
                            <div className="flex items-center gap-2">
                                {[-50, -30, -20, -10, 10, 20, 50].map(pct => (
                                    <button key={pct} onClick={() => setStressPercent(pct)}
                                        className={`px-2 py-1 rounded-lg text-[9px] font-bold transition-all border ${stressPercent === pct ? 'bg-blue-500 text-white border-blue-500' : 'bg-white/5 text-gray-500 border-white/10 hover:bg-white/10'}`}
                                    >{pct > 0 ? '+' : ''}{pct}%</button>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-3 gap-4">
                        <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5">
                            <span className="text-[9px] text-gray-600 uppercase tracking-widest">Base Value</span>
                            <div className="text-lg font-black font-mono text-white">{currency.format(totalValue)}</div>
                        </div>
                        <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5">
                            <span className="text-[9px] text-gray-600 uppercase tracking-widest">Post-Stress</span>
                            <div className={`text-lg font-black font-mono ${totalDelta >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>{currency.format(stressedTotal)}</div>
                        </div>
                        <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5">
                            <span className="text-[9px] text-gray-600 uppercase tracking-widest">Impact</span>
                            <div className={`text-lg font-black font-mono ${totalDelta >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                {totalDelta >= 0 ? '+' : ''}{currency.format(totalDelta)}
                            </div>
                        </div>
                    </div>

                    <div className="space-y-2 max-h-60 overflow-y-auto custom-scrollbar">
                        {stressedWithAlloc.filter(a => a.symbol !== 'USD').map(a => (
                            <div key={a.symbol} className="flex items-center gap-4 p-3 rounded-xl bg-white/[0.01] border border-white/5">
                                <div className="flex items-center gap-2 w-24">
                                    {LOGO_MAPPING[a.symbol] && <img src={LOGO_MAPPING[a.symbol]} alt={a.symbol} className="w-5 h-5" />}
                                    <span className="text-xs font-black text-white">{a.symbol}</span>
                                </div>
                                <div className="flex-1">
                                    <div className="flex items-center gap-2 mb-1">
                                        <div className="flex-1 h-2 bg-white/5 rounded-full overflow-hidden">
                                            <div className={`h-full rounded-full transition-all ${a.delta >= 0 ? 'bg-emerald-500' : 'bg-rose-500'}`}
                                                style={{ width: `${Math.min(a.stressedAlloc, 100)}%` }}
                                            ></div>
                                        </div>
                                        <span className="text-[10px] font-mono text-gray-400 w-12 text-right">{a.stressedAlloc.toFixed(1)}%</span>
                                    </div>
                                </div>
                                <div className="flex flex-col items-end w-28">
                                    <span className="text-xs font-mono text-white">{currency.format(a.stressedValue)}</span>
                                    <span className={`text-[9px] font-mono ${a.delta >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                        {a.delta >= 0 ? '+' : ''}{currency.format(a.delta)}
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* ΓòÉΓòÉΓòÉ CONCENTRATION HEATMAP ΓòÉΓòÉΓòÉ */}
                    <div className="glass-card p-6 space-y-4">
                        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">Concentration Map</h3>
                        <div className="grid grid-cols-3 gap-2">
                            {sortedByAlloc.map(a => {
                                const intensity = Math.min(a.allocation / 50, 1);
                                const isOverweight = a.allocation > a.targetAllocation + 5;
                                const isUnderweight = a.allocation < a.targetAllocation - 5;
                                return (
                                    <div key={a.symbol}
                                        className={`p-3 rounded-xl border transition-all ${isOverweight ? 'border-amber-500/30 bg-amber-500/10' :
                                            isUnderweight ? 'border-blue-500/30 bg-blue-500/10' :
                                                'border-white/5 bg-white/[0.02]'
                                            }`}
                                        style={{ opacity: 0.4 + intensity * 0.6 }}
                                    >
                                        <div className="flex items-center justify-between mb-1">
                                            <div className="flex items-center gap-1.5">
                                                {LOGO_MAPPING[a.symbol] && <img src={LOGO_MAPPING[a.symbol]} alt="" className="w-4 h-4" />}
                                                <span className="text-[10px] font-black text-white">{a.symbol}</span>
                                            </div>
                                            {isOverweight && <span className="text-[8px] text-amber-400">OVER</span>}
                                            {isUnderweight && <span className="text-[8px] text-blue-400">UNDER</span>}
                                        </div>
                                        <div className="text-sm font-black font-mono text-white">{a.allocation.toFixed(1)}%</div>
                                        <div className="text-[9px] text-gray-600 font-mono">target: {a.targetAllocation.toFixed(1)}%</div>
                                    </div>
                                );
                            })}
                        </div>
                        {overlapping.length > 0 && (
                            <div className="p-3 rounded-xl bg-amber-500/5 border border-amber-500/20 text-[9px] text-amber-400">
                                ΓÜá∩╕Å Cross-account overlap: <span className="font-bold">{overlapping.join(', ')}</span> ΓÇö held in both accounts
                            </div>
                        )}
                    </div>

                    {/* ΓòÉΓòÉΓòÉ DRAWDOWN TRACKER ΓòÉΓòÉΓòÉ */}
                    <div className="glass-card p-6 space-y-4">
                        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">Drawdown from Cost Basis</h3>
                        <div className="space-y-3">
                            {drawdowns.map(a => (
                                <div key={a.symbol} className="flex items-center gap-3">
                                    <div className="flex items-center gap-2 w-20">
                                        {LOGO_MAPPING[a.symbol] && <img src={LOGO_MAPPING[a.symbol]} alt="" className="w-4 h-4" />}
                                        <span className="text-[10px] font-bold text-white">{a.symbol}</span>
                                    </div>
                                    <div className="flex-1 h-3 bg-white/5 rounded-full overflow-hidden relative">
                                        {a.drawdownPct >= 0 ? (
                                            <div className="h-full bg-emerald-500/60 rounded-full transition-all" style={{ width: `${Math.min(Math.abs(a.drawdownPct), 100)}%` }}></div>
                                        ) : (
                                            <div className="h-full bg-rose-500/60 rounded-full transition-all" style={{ width: `${Math.min(Math.abs(a.drawdownPct), 100)}%` }}></div>
                                        )}
                                    </div>
                                    <span className={`text-xs font-mono font-bold w-16 text-right ${a.drawdownPct >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                        {a.drawdownPct >= 0 ? '+' : ''}{a.drawdownPct.toFixed(1)}%
                                    </span>
                                    <span className="text-[9px] text-gray-600 font-mono w-16 text-right">{currency.format(a.gainLoss || 0)}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* ΓòÉΓòÉΓòÉ CROSS-ACCOUNT SUMMARY ΓòÉΓòÉΓòÉ */}
                <div className="glass-card p-6 space-y-4">
                    <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">Cross-Account Risk Summary</h3>
                    <div className="grid grid-cols-3 gap-4">
                        <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5">
                            <span className="text-[9px] text-gray-600 uppercase">Active ({activeAccount.toUpperCase()})</span>
                            <div className="text-base font-black font-mono text-white">{currency.format(totalValue)}</div>
                            <span className="text-[9px] text-gray-500">{((totalValue / combinedTotal) * 100).toFixed(0)}% of combined</span>
                        </div>
                        <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5">
                            <span className="text-[9px] text-gray-600 uppercase">Other ({otherAccountId.toUpperCase()})</span>
                            <div className="text-base font-black font-mono text-gray-400">{currency.format(otherTotal)}</div>
                            <span className="text-[9px] text-gray-500">{((otherTotal / combinedTotal) * 100).toFixed(0)}% of combined</span>
                        </div>
                        <div className="p-4 rounded-xl bg-white/[0.02] border border-white/5">
                            <span className="text-[9px] text-gray-600 uppercase">Combined AUM</span>
                            <div className="text-base font-black font-mono text-blue-400">{currency.format(combinedTotal)}</div>
                            <span className="text-[9px] text-gray-500">Across 2 Roth IRAs</span>
                        </div>
                    </div>
                </div>
              </div>
            </div>
        </>
    );
}
